import { autoRetry, type RetryReason } from "@yaebal/again";
import { createBot, TelegramError } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/again/.env first (copy .env.example)");
	process.exit(1);
}

const retryCounts: Record<RetryReason, number> = {
	retry_after: 0,
	rate_limit_backoff: 0,
	internal: 0,
};

let totalRetryDelayMs = 0;

const bot = createBot(token).install(
	autoRetry({
		maxRetries: 5,
		maxDelayMs: 60_000,
		retryAfterPaddingMs: 250,
		jitter: 0.1,
		onRetry: (event) => {
			retryCounts[event.reason] = (retryCounts[event.reason] ?? 0) + 1;
			totalRetryDelayMs += event.delayMs;
			console.log(
				`retry ${event.method}: reason=${event.reason} attempt=${event.attempt} delay=${event.delayMs}ms`,
			);
		},
	}),
);

bot.command("start", (ctx) =>
	ctx.reply(
		"This bot uses @yaebal/again. Try /burst to send a burst and /stats to inspect retry metrics.",
	),
);

bot.command("burst", async (ctx) => {
	await ctx.reply("sending 45 messages; any 429 retry_after will be awaited and retried");

	for (let index = 1; index <= 45; index++) {
		await ctx.send(`burst message ${index}/45`);
	}

	return ctx.reply("burst finished");
});

bot.command("stats", (ctx) =>
	ctx.reply(
		[
			"again retry stats",
			`retry_after: ${retryCounts.retry_after}`,
			`rate_limit_backoff: ${retryCounts.rate_limit_backoff}`,
			`internal: ${retryCounts.internal}`,
			`total retry delay: ${totalRetryDelayMs}ms`,
		].join("\n"),
	),
);

bot.onError((error, ctx) => {
	if (error instanceof TelegramError) {
		console.error("telegram api error", {
			method: error.method,
			code: error.code,
			parameters: error.parameters,
		});
	} else {
		console.error("handler error", error);
	}

	return ctx.reply("the request failed after all retries; check the example logs");
});

await bot.start();
console.log("again example bot is running");

import { AiLimitError, ai, openaiCompatible } from "@yaebal/ai";
import { createBot } from "yaebal";

// an ai chat bot with streamed answers, per-user memory and polite rate limits.
//
//   pnpm --filter @yaebal/example-ai-chat dev
//
// needs BOT_TOKEN and an llm in .env (copy .env.example): any openai-compatible
// provider works — openai itself, openrouter, groq, or a local ollama.

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/ai-chat/.env first (copy .env.example)");
	process.exit(1);
}

const bot = createBot(token).install(
	ai({
		// ollama out of the box; flip the env vars for any hosted provider.
		model: openaiCompatible({
			model: process.env.AI_MODEL ?? "llama3.2",
			baseUrl: process.env.AI_BASE_URL ?? "http://localhost:11434/v1",
			apiKey: process.env.AI_API_KEY,
		}),
		system:
			"you are a friendly telegram bot. answer briefly — a phone screen, not an essay. " +
			"match the user's language.",
		// memory is on by default (per user per chat, windowed); limits keep the bill sane.
		limits: { perUser: "20/h" },
	}),
);

bot.command("start", (ctx) =>
	ctx.send("hi! i'm an ai chat bot — just write to me. /reset wipes my memory of us."),
);

bot.command("reset", async (ctx) => {
	await ctx.ai.reset();
	await ctx.send("clean slate. who are you again?");
});

bot.on("message:text", async (ctx) => {
	try {
		// in private chats this streams via telegram's native draft animation
		// ("Thinking…", then a live-growing preview); in groups it grows a message
		// through throttled edits with a ▍ cursor. long answers split automatically.
		await ctx.ai.replyStream(ctx.text);
	} catch (error) {
		if (error instanceof AiLimitError) {
			const minutes = Math.ceil(error.retryAfterMs / 60_000);
			await ctx.reply(`easy! you hit the hourly limit — try again in ~${minutes}m.`);
			return;
		}
		throw error;
	}
});

bot.onError((error, ctx) => {
	console.error("update failed", ctx?.update?.update_id, error);
});

await bot.start();
console.log("ai-chat bot is up");

import { analytics, analyticsAdmin, consoleAdapter, memoryAdapter, p } from "@yaebal/analytics";
import { createBot, InlineKeyboard } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/analytics/.env first (copy .env.example)");
	process.exit(1);
}

// set ADMIN_ID in .env to your telegram user id to unlock /analytics; otherwise everyone can use
// it (fine for this demo, but pass a real allow-list/role check in production).
const adminId = process.env.ADMIN_ID ? Number(process.env.ADMIN_ID) : undefined;

// query()-able, so /analytics can read it back — swap for sqliteAdapter/clickhouseAdapter in
// production; this one lives only in memory for the demo.
const store = memoryAdapter();

const bot = createBot(token)
	.install(
		analytics({
			// event names + properties are checked against this catalog — try renaming "purchase"
			// below to "purchse" and watch `tsc` catch it before you ever run the bot.
			events: {
				start: true, // declared, untyped — any properties allowed
				purchase: { props: p.object({ amount: p.number(), plan: p.optional(p.string()) }) },
			},
			adapters: [consoleAdapter(), store],
			// no manual ctx.track() needed for commands/buttons/messages — see the handlers below
			autoTrack: ["commands", "callback_queries", "messages"],
			// merged onto every event, typed and untyped alike
			context: (ctx) => ({ languageCode: ctx.from?.language_code }),
			onError: (error, event) => console.error("[analytics] failed:", event.name, error),
		}),
	)
	.install(
		analyticsAdmin({
			isAdmin: (ctx) => adminId === undefined || ctx.from?.id === adminId,
			adapter: store,
		}),
	);

bot.command("start", (ctx) => {
	ctx.track("start", { source: "deeplink" });
	return ctx.reply(
		"analytics demo — try /buy, /identify, /menu, /analytics (admin report), or just send a message.\n\n" +
			"autoTrack is on for commands, buttons, and messages, so most of what you do here gets " +
			"tracked without a single ctx.track() call.",
	);
});

bot.command("buy", (ctx) => {
	// name + props type-checked against the `events` catalog above
	ctx.track("purchase", { amount: 9, plan: "pro" });
	return ctx.reply("thanks! logged as a typed `purchase` event (see the console).");
});

bot.command("identify", (ctx) => {
	ctx.identify({ plan: "pro", locale: ctx.from?.language_code });
	return ctx.reply(
		"identified you to every adapter that supports it (posthog-style person props).",
	);
});

bot.command("menu", (ctx) =>
	ctx.reply("press the button — the click is auto-captured too", {
		reply_markup: new InlineKeyboard().text("ping", "ping").build(),
	}),
);

bot.callbackQuery("ping", async (ctx) => {
	await ctx.answerCallbackQuery();
	await ctx.reply("pong");
});

bot.on("message:text", (ctx) =>
	ctx.reply(`you said: ${ctx.text} (auto-tracked as message_received)`),
);

bot.onStart(() =>
	console.log("bot ready — analytics.flush() will run on bot.onStop automatically"),
);

bot.start();

import { applyRedaction, auditAdmin, auditLog, chatSink, memorySink } from "@yaebal/audit-log";
import { createBot } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/audit-log/.env first (copy .env.example)");
	process.exit(1);
}

// set ADMIN_ID in .env to your telegram user id to unlock /audit; otherwise everyone can use it
// (fine for this demo, but pass a real allow-list/role check in production).
const adminId = process.env.ADMIN_ID ? Number(process.env.ADMIN_ID) : undefined;
const isAdmin = (ctx: { from?: { id: number } }) =>
	adminId === undefined || ctx.from?.id === adminId;

// a bounded ring buffer of recent audit entries, readable from /status without a separate db.
const recent = memorySink({ limit: 20 });

// bot.api is available as soon as createBot() returns — independent of what's installed
// later — so chatSink(bot, ...) can be built before auditLog() is installed on bot.
const bot = createBot(token);

const audit = auditLog({
	sinks: [
		recent,
		// only wire chatSink if you've set an admin chat — it ships errors straight into
		// that chat via the bot's own sendMessage, deduped and rate-limited.
		...(process.env.ADMIN_CHAT_ID
			? [chatSink(bot, { chatId: process.env.ADMIN_CHAT_ID, minLevel: "error" as const })]
			: []),
	],
});

bot.install(audit);
// telegram-native ops surface for the counters auditLog() tracks: /audit, /audit flush
bot.install(auditAdmin({ logger: audit, isAdmin }));

bot.command("start", (ctx) =>
	ctx.reply(
		[
			"this bot demos @yaebal/audit-log. try:",
			"/whoami — a normal reply; watch the terminal for the update + api.call/api.result events",
			"/secret — shows redaction masking a fake secret_token and phone_number before logging",
			"/status — the last few audit entries, read straight out of a memorySink",
			"/boom — throws inside the handler; still logged (with the error), still propagates",
			"/audit — auditLog()'s running counters (admin command; open unless ADMIN_ID is set)",
		].join("\n"),
	),
);

bot.command("whoami", (ctx) => ctx.reply(`you are ${ctx.from?.id} in chat ${ctx.chat?.id}`));

bot.command("secret", async (ctx) => {
	const before = {
		chat_id: ctx.chat?.id,
		secret_token: "sk_live_abc123",
		phone_number: "+15551234567",
		note: "this field isn't a known secret key, so it passes through unmasked",
	};
	const after = applyRedaction(before);

	console.log("[demo] before redaction:", before);
	console.log("[demo] after  redaction:", after);
	await ctx.reply(
		"check the terminal — secret_token and phone_number just got masked, `note` didn't",
	);
});

bot.command("status", async (ctx) => {
	const lines = recent.events
		.slice(-5)
		.map((event) => `${event.kind}${"method" in event ? ` ${event.method}` : ""}`);
	await ctx.reply(lines.length > 0 ? lines.join("\n") : "no audit entries yet");
});

bot.command("boom", () => {
	throw new Error("deliberate crash — check the terminal for the update event's `error` field");
});

bot.start();

import { autoAnswer } from "@yaebal/auto-answer";
import { createBot, InlineKeyboard } from "yaebal";

// a tour of @yaebal/auto-answer: the "deadline" default (a handler's own alert always wins
// the race, a forgotten handler still gets a fallback ack), skipAutoAnswer() for a callback
// answered later from off to the side, and filter() for callbacks another plugin already
// answers its own way.
//
//   pnpm --filter @yaebal/example-auto-answer dev   (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/auto-answer/.env first (copy .env.example)");
	process.exit(1);
}

const COMMANDS = [
	{ command: "start", description: "a handler that answers fast — its own alert wins" },
	{ command: "forgot", description: "a handler that never answers — the fallback fires" },
	{ command: "queue", description: "skipAutoAnswer() + answering later from a queued job" },
	{ command: "raw", description: "filter() — a callback another plugin answers itself" },
	{ command: "help", description: "list every command" },
];

const bot = createBot(token)
	.install(
		autoAnswer({
			// "deadline" is the default — spelled out here for the tour. a handler has 1.5s to
			// answer on its own before the plugin fills the gap with an empty ack.
			mode: "deadline",
			timeout: 1500,
			// the "raw:" callbacks below answer themselves — let them.
			filter: (ctx) => !ctx.callbackQuery.data?.startsWith("raw:"),
			onAnswer: (ctx) => console.log("auto-answered", ctx.callbackQuery.id),
			onError: (error, ctx) => console.warn("auto-answer failed", ctx.callbackQuery.id, error),
		}),
	)

	.command("start", (ctx) =>
		ctx.reply("a handler that answers fast keeps its own alert — try it:", {
			reply_markup: new InlineKeyboard().text("show alert", "alert:go"),
		}),
	)
	.callbackQuery("alert:go", (ctx) =>
		// well inside the 1.5s deadline — this alert reaches the client untouched, the plugin
		// never gets a chance to fire its own empty ack.
		ctx.answerCallbackQuery({ text: "still yours to control ✨", show_alert: true }),
	)

	.command("forgot", (ctx) =>
		ctx.reply("this handler never calls answerCallbackQuery — the spinner still clears:", {
			reply_markup: new InlineKeyboard().text("press me", "forgot:go"),
		}),
	)
	.callbackQuery("forgot:go", (ctx) => ctx.reply("handled — no answerCallbackQuery call in sight"))

	.command("queue", (ctx) =>
		ctx.reply("archiving happens off to the side — the plugin won't fill the gap for this one:", {
			reply_markup: new InlineKeyboard().text("archive", "queue:go"),
		}),
	)
	.callbackQuery("queue:go", async (ctx) => {
		// tell the plugin this update is spoken for, then answer whenever the "job" finishes —
		// well past the deadline, which would otherwise have already answered for it.
		ctx.skipAutoAnswer();
		await ctx.reply("queued for archiving…");

		setTimeout(() => {
			void ctx.answerCallbackQuery({ text: "archived ✅" });
		}, 2000);
	})

	.command("raw", (ctx) =>
		ctx.reply("this callback matches the filter above — it answers itself:", {
			reply_markup: new InlineKeyboard().text("raw button", "raw:go"),
		}),
	)
	.callbackQuery("raw:go", (ctx) =>
		ctx.answerCallbackQuery({ text: "answered outside the plugin, by filter() design" }),
	)

	.command("help", (ctx) =>
		ctx.reply(COMMANDS.map((c) => `/${c.command} — ${c.description}`).join("\n")),
	)

	.onError((error, ctx) => {
		console.error(`update ${ctx.update.update_id} failed:`, error);
	})
	.onStart(async (info) => {
		// publish the command menu so it shows up in the telegram "/" picker
		await bot.api.call("setMyCommands", { commands: COMMANDS }).catch(() => {});
		console.log(`✨ @${info.username} is live — DM it /start`);
	});

// graceful shutdown
process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { autoRetry } from "@yaebal/again";
import { cache } from "@yaebal/cache";
import { back, button, type DialogDef, dialogs, switchTo } from "@yaebal/morda";
import { prompt } from "@yaebal/prompt";
import { ask, defineScene, scenes } from "@yaebal/scenes";
import { throttle } from "@yaebal/throttle";
import {
	and,
	bold,
	type Context,
	callbackData,
	createBot,
	filters,
	format,
	html,
	InlineKeyboard,
	i18n,
	italic,
	media,
	type Plugin,
	session,
} from "yaebal";

// a single-file tour of the yaebal stack. each command shows off one plugin.
//
//   pnpm --filter @yaebal/example-basic dev   (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/basic/.env first (copy .env.example)");
	process.exit(1);
}

// the command menu telegram shows in the "/" picker — registered on start
const COMMANDS = [
	{ command: "start", description: "greeting + an inline keyboard" },
	{ command: "count", description: "a per-chat counter (session)" },
	{ command: "whoami", description: "getChat, memoized for a minute (cache)" },
	{ command: "menu", description: "a two-window dialog (morda)" },
	{ command: "photo", description: "send a photo by url (media)" },
	{ command: "lang", description: "toggle the locale (i18n)" },
	{ command: "register", description: "a name → age wizard (scenes)" },
	{ command: "name", description: "ask once, handle the reply (prompt)" },
	{ command: "help", description: "list every command" },
];

// i18n tables; ctx.t / ctx.changeLanguage become available after install.
// `as const` turns on typed keys + typed params for ctx.t; the first locale a
// user sees is auto-detected from telegram's language_code.
const locales = {
	en: { hello: "hi {who}! switched to english." },
	ru: { hello: "привет {who}! язык переключён на русский." },
} as const;

// a step-by-step wizard (scenes): name → age, with typed state and validation.
// answers land in ctx.scene.state; invalid input re-asks; /help etc. still work
// mid-wizard because commands bypass an active scene by default.
const wizard = defineScene<Context, { name: string; age: number }>({
	steps: [
		ask("name", { question: "what's your name?" }),
		ask("age", {
			question: (ctx) => `hi, ${ctx.scene.state.name}! how old are you?`,
			parse: (text) => (/^\d+$/.test(text) ? Number(text) : undefined),
			invalid: "age is a number — try again",
		}),
	],
	onLeave: (ctx, info) =>
		info.reason === "finish" &&
		ctx.reply(`${ctx.scene.state.name}, ${ctx.scene.state.age} — noted ✨`),
});

// a two-window dialog (morda): main ↔ settings, with stack navigation
const menu: DialogDef = {
	main: () => ({
		text: "🏠 main menu",
		keyboard: [
			[switchTo("⚙️ settings", "settings")],
			[
				button("🔔 ping", {
					id: "ping",
					onClick: (c) => c.answerCallbackQuery({ text: "pong 🏓" }),
				}),
			],
		],
	}),
	settings: () => ({ text: "⚙️ settings", keyboard: [[back("← back")]] }),
};

// a trivial context plugin — exercises install() and the typed-dependency flow
const stamp: Plugin<Context, { startedAt: Date }> = (c) => c.decorate({ startedAt: new Date() });

// typed callback_data: vote.pack({ choice }) → string, vote.unpack(data) → { choice } | undefined
const vote = callbackData("vote", { choice: String });

const bot = createBot(token)
	// retry on 429/flood-wait and transient 5xx, and throttle outgoing calls
	.install(autoRetry())
	.install(throttle())
	// ctx.cache.get/set/wrap; ttl memoization for api calls, dedupes concurrent misses
	.install(cache({ ttl: 60_000 }))
	// install a plugin; `startedAt` now flows into every handler's context type
	.install(stamp)
	// per-chat session; `ctx.session` is now typed { count: number }
	.install(session({ initial: () => ({ count: 0 }) }))
	// dialogs engine; `ctx.dialog` (start/push/back) now available
	.install(dialogs(menu))
	// i18n; `ctx.t` / `ctx.changeLanguage` now available
	.install(i18n({ defaultLocale: "en", locales }))
	// scenes (wizards) and prompt (one-shot next message)
	.install(scenes({ register: wizard }))
	.install(prompt())
	// async per-request enrichment — types flow into the handlers below
	.derive((ctx) => ({
		who: ctx.from?.username ? `@${ctx.from.username}` : (ctx.from?.first_name ?? "stranger"),
	}))
	// @yaebal/filters: deep link — t.me/<bot>?start=ref_<id> lands here, payload parsed.
	// registered before the plain /start handler so referred starts don't fall through to it
	.filter(filters.deeplink(/^ref_(\d+)$/), (ctx) =>
		ctx.reply(`welcome! you were referred by user ${ctx.match[1]}`),
	)
	// command router: matches /start, strips @botname, parses args
	.command("start", (ctx) =>
		ctx.send(
			format`hey, ${bold(ctx.who)}! 🐴
this is ${italic("yaebal")} — Yet Another tElegram Bot Api Library.
try /help, or tap a button below.`,
			{
				reply_markup: new InlineKeyboard()
					.text("👍", vote.pack({ choice: "up" }))
					.text("👎", vote.pack({ choice: "down" }))
					.build(),
			},
		),
	)
	// session in action: a per-chat counter
	.command("count", (ctx) => {
		ctx.session.count++;
		return ctx.reply(`you've called /count ${ctx.session.count} time(s)`);
	})
	// open the morda dialog
	.command("menu", (ctx) => ctx.dialog.start("main"))
	// cache: getChat memoized for 60s — a burst of /whoami only calls the api once
	.command("whoami", async (ctx) => {
		const chat = await ctx.cache.wrap(`chat:${ctx.chat.id}`, () => ctx.getChat());
		return ctx.reply(chat.title ?? "just you and me, in a private chat");
	})
	// media: send a photo by URL (or media.path(...) / media.buffer(...))
	.command("photo", (ctx) =>
		ctx.sendPhoto(media.url("https://picsum.photos/400"), { caption: "a random picture" }),
	)
	// i18n: toggle locale and reply in the new language
	.command("lang", async (ctx) => {
		await ctx.changeLanguage(ctx.locale === "ru" ? "en" : "ru");
		return ctx.reply(ctx.t("hello", { who: ctx.who }));
	})
	// scenes: start the wizard
	.command("register", (ctx) => ctx.scene.enter("register"))
	// prompt: ask once, handle the next message
	.command("name", (ctx) => ctx.prompt("what's your name?", (c) => c.reply(`hi, ${c.text}!`)))
	// @yaebal/filters: composed filter — /help only in private chats, with an fmt html reply
	.filter(and(filters.isPrivate, filters.command("help")), (ctx) =>
		ctx.send(
			html`<b>commands</b>
${COMMANDS.map((c) => `/${c.command} — ${c.description}`).join("\n")}`,
		),
	)
	// hears: regex match on text, exposes ctx.match
	.hears(/^(ping|пинг)$/i, (ctx) => ctx.reply("pong"))
	// @yaebal/filters: regex filter — exposes ctx.match, replies with html bold/italic via @yaebal/fmt
	.filter(filters.regex(/^(hello|привет)/i), (ctx) =>
		ctx.send(html`<b>hello!</b> you wrote: <i>${ctx.match[0]}</i>`),
	)
	// @yaebal/filters: media shorthands — or() unites branches, ctx.message is narrowed
	.filter(filters.or(filters.photo, filters.video), (ctx) => ctx.reply("nice media! 📸"))
	// filter query: only text messages; ctx.text is narrowed to string
	.on("message:text", (ctx) => ctx.reply(format`you said: ${bold(ctx.text)}`))
	// typed callback buttons: only "vote:*" data, payload parsed via callback-data
	.callbackQuery(vote.pattern, async (ctx) => {
		const choice = vote.unpack(ctx.callbackQuery.data ?? "")?.choice;
		await ctx.answer(choice === "up" ? "liked 👍" : "disliked 👎");
	})
	.onError((error, ctx) => {
		console.error(`update ${ctx.update.update_id} failed:`, error);
	})
	.onStart(async (info) => {
		// publish the command menu so it shows up in the telegram "/" picker
		await bot.api.call("setMyCommands", { commands: COMMANDS }).catch(() => {});
		console.log(`✨ @${info.username} is live — DM it /start`);
	});
// graceful shutdown
process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { Broadcast, type BroadcastEvent, type BroadcastJobHandle } from "@yaebal/broadcast";
import { createBot } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/broadcast/.env first (copy .env.example)");
	process.exit(1);
}

const adminId = process.env.ADMIN_ID ? Number(process.env.ADMIN_ID) : undefined;
const subscribers = new Set<number>();
const jobs = new Map<string, BroadcastJobHandle>();
const recentEvents: string[] = [];

const bot = createBot(token);

function remember(event: BroadcastEvent): void {
	recentEvents.push(event.type);
	if (recentEvents.length > 10) recentEvents.shift();
}

function isAdmin(userId: number | undefined): boolean {
	return adminId === undefined || userId === adminId;
}

function requireAdmin(userId: number | undefined): string | undefined {
	if (isAdmin(userId)) return undefined;
	return "this command is restricted. set ADMIN_ID in .env to your telegram user id.";
}

const broadcaster = new Broadcast(bot.api, {
	concurrency: 3,
	rateLimit: { limit: 20, windowMs: 1_000 },
	retry: { attempts: 5, fixedDelayMs: 1_000 },
	onEvent: remember,
}).type("digest", (chatId: number, text: string) =>
	bot.api.sendMessage({
		chat_id: chatId,
		text,
		disable_notification: true,
	}),
);

bot
	.command("start", async (ctx) => {
		subscribers.add(ctx.chat.id);

		await ctx.reply(`you are subscribed to the broadcast demo.

try /status to see worker metrics.
admin commands: /broadcast text, /pause job_id, /resume job_id, /cancel job_id.`);
	})
	.command("subscribe", async (ctx) => {
		subscribers.add(ctx.chat.id);
		return ctx.reply(`subscribed. audience size: ${subscribers.size}.`);
	})
	.command("unsubscribe", async (ctx) => {
		subscribers.delete(ctx.chat.id);
		return ctx.reply(`unsubscribed. audience size: ${subscribers.size}.`);
	})
	.command("broadcast", async (ctx) => {
		const denied = requireAdmin(ctx.from?.id);
		if (denied) return ctx.reply(denied);

		const text = ctx.args.join(" ").trim();
		if (!text) return ctx.reply("usage: /broadcast text to send");

		const audience = [...subscribers];
		if (audience.length === 0)
			return ctx.reply("no subscribers yet. ask users to send /start first.");

		const job = await broadcaster.start(
			"digest",
			audience.map((chatId) => [chatId, text] as const),
			{ metadata: { requestedBy: ctx.from?.id } },
		);
		jobs.set(job.id, job);

		await ctx.reply(`queued ${audience.length} deliveries.
job id: ${job.id}`);

		void job
			.wait()
			.then((result) =>
				ctx.reply(
					`job ${result.jobId} finished: ${result.sent} sent, ${result.skipped} skipped, ${result.failed} failed.`,
				),
			);
	})
	.command("status", async (ctx) => {
		const latest = (await broadcaster.listJobs()).slice(-5).reverse();
		const lines = latest.map(
			(job) =>
				`${job.id}: ${job.status}, ${job.sent}/${job.total} sent, ${job.skipped} skipped, ${job.failed} failed`,
		);
		const metrics = broadcaster.metrics;

		return ctx.reply(`audience: ${subscribers.size}
active deliveries: ${metrics.active}
events: ${recentEvents.join(", ") || "none"}

recent jobs:
${lines.join("\n") || "none"}`);
	})
	.command("pause", async (ctx) =>
		controlJob(ctx.args[0], "pause", (job) => job.pause(), ctx.reply.bind(ctx)),
	)
	.command("resume", async (ctx) =>
		controlJob(ctx.args[0], "resume", (job) => job.resume(), ctx.reply.bind(ctx)),
	)
	.command("cancel", async (ctx) =>
		controlJob(ctx.args[0], "cancel", (job) => job.cancel(), ctx.reply.bind(ctx)),
	)
	.on("message:text", (ctx) => ctx.reply("send /start to subscribe or /status to inspect jobs."))
	.onStart(async (info) => {
		await bot.api
			.call("setMyCommands", {
				commands: [
					{ command: "start", description: "subscribe to the demo" },
					{ command: "broadcast", description: "admin: queue a broadcast" },
					{ command: "status", description: "show broadcast metrics" },
					{ command: "pause", description: "admin: pause a job" },
					{ command: "resume", description: "admin: resume a job" },
					{ command: "cancel", description: "admin: cancel a job" },
				],
			})
			.catch(() => {});

		console.log(`@${info.username} is live. admin id: ${adminId ?? "not set"}`);
	})
	.onStop(() => broadcaster.stop({ drain: true }));

async function controlJob(
	id: string | undefined,
	verb: string,
	action: (job: BroadcastJobHandle) => Promise<void>,
	reply: (text: string) => Promise<unknown>,
): Promise<unknown> {
	if (!id) return reply(`usage: /${verb} job_id`);

	const job = jobs.get(id);
	if (!job) return reply(`unknown job: ${id}`);

	await action(job);
	return reply(`${verb}d job ${id}.`);
}

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { type Commands, commands } from "@yaebal/commands";
import { type Context, createBot, session } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/commands/.env first (copy .env.example)");
	process.exit(1);
}

interface Stats {
	hits: number;
}

// the registry is generic over the bot's accumulated context: handlers below see
// ctx.session (from @yaebal/session) plus the typed ctx.command / ctx.args
type BotContext = Context & { session: Stats };

// the explicit annotation lets the /help handler below reference `cmd` itself
const cmd: Commands<BotContext> = commands<BotContext>()
	// ["name", ...aliases] — /go works too, only /start shows in the menu
	.add(["start", "go"], { default: "start the tour", ru: "начать тур" }, (ctx) => {
		ctx.session.hits++;
		return ctx.reply(
			[
				`hi! this is the @yaebal/commands tour (you typed /${ctx.command}).`,
				"try /help for the full list, or /echo one two.",
			].join("\n"),
		);
	})
	.add("echo", { default: "echo the arguments", ru: "повторить аргументы" }, (ctx) => {
		ctx.session.hits++;
		return ctx.reply(ctx.args.length > 0 ? ctx.args.join(" ") : "give me arguments: /echo one two");
	})
	.add("stats", { default: "commands handled for you", ru: "счётчик команд" }, (ctx) => {
		ctx.session.hits++;
		return ctx.reply(`commands handled for you this session: ${ctx.session.hits}`);
	})
	.add("help", { default: "list all commands", ru: "список команд" }, (ctx) => {
		ctx.session.hits++;
		return ctx.reply(
			cmd
				.list({ languageCode: ctx.from?.language_code })
				.map((c) => `/${c.command} — ${c.description}`)
				.join("\n"),
		);
	})
	// menu-only: no handlers here — the /about handler lives on the bot chain below
	.add("about", { default: "what this bot is", ru: "что это за бот" })
	// hidden: handled, but never shown in any menu
	.hidden("debug", (ctx) =>
		ctx.reply(JSON.stringify({ command: ctx.command, args: ctx.args }, null, 2)),
	)
	// hidden lifecycle demo: /menu sync | push | clear
	.hidden("menu", async (ctx) => {
		const [action] = ctx.args;

		if (action === "clear") {
			const cleared = await cmd.unregister(ctx.api);
			return ctx.reply(`cleared ${cleared.length} menus — the / picker is empty now`);
		}
		if (action === "push") {
			const pushed = await cmd.register(ctx.api);
			return ctx.reply(`pushed ${pushed.length} menus unconditionally`);
		}

		const { pushed, skipped } = await cmd.sync(ctx.api);
		return ctx.reply(`synced: ${pushed.length} pushed, ${skipped.length} unchanged`);
	});

// scoped: group admins see /pin_rules in their menu; everyone else only /start../about.
// the scope only affects the menu — the handler still runs for anyone who types it.
cmd
	.scoped({ type: "all_chat_administrators" })
	.add("pin_rules", { default: "post the group rules", ru: "правила группы" }, (ctx) =>
		ctx.reply("rules: be kind and use /help. (this menu entry is admin-only)"),
	);

const bot = createBot(token)
	.install(session<Stats>({ initial: () => ({ hits: 0 }) }))
	.install(cmd.plugin())
	// the handler for the menu-only /about entry — registry and handlers are decoupled
	.command("about", (ctx) =>
		ctx.reply(
			[
				"a focused tour of @yaebal/commands:",
				"typed registry, localized menus, scopes, aliases, hidden commands,",
				"and diff-based menu sync. see examples/commands/src/index.ts.",
			].join("\n"),
		),
	)
	.on("message:text", (ctx) => ctx.reply("that's not a command i know — try /help."))
	.onStart(async (info) => {
		// diff-aware: default + ru menus, admin scope included, pushed only when changed
		const result = await cmd.sync(bot.api).catch(() => undefined);
		const status = result
			? `${result.pushed.length} pushed, ${result.skipped.length} unchanged`
			: "sync failed";
		console.log(`@${info.username} commands tour is live — menus: ${status}`);
	});

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { commands } from "@yaebal/commands";
import { pagination } from "@yaebal/pagination";
import { ratelimiter } from "@yaebal/ratelimiter";
import {
	and,
	type Context,
	callbackData,
	createBot,
	type Dict,
	field,
	filters,
	html,
	InlineKeyboard,
	i18n,
	type LocaleLike,
	session,
	type TFn,
} from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/commerce-suite/.env first (copy .env.example)");
	process.exit(1);
}

interface Product {
	id: number;
	name: string;
	price: number;
	tag: string;
}

interface CartSession {
	items: Record<number, number>;
}

const products: Product[] = [
	{ id: 1, name: "neon hoodie", price: 79, tag: "drop" },
	{ id: 2, name: "bot api field guide", price: 29, tag: "book" },
	{ id: 3, name: "callback keychain", price: 9, tag: "gear" },
	{ id: 4, name: "typed plugin pass", price: 149, tag: "vip" },
	{ id: 5, name: "edge webhook kit", price: 59, tag: "cloud" },
	{ id: 6, name: "album forge preset", price: 39, tag: "media" },
	{ id: 7, name: "ratelimit shield", price: 19, tag: "ops" },
	{ id: 8, name: "session vault", price: 49, tag: "state" },
];

// `as const` keeps the templates as literal types, so ctx.t gets typed keys and
// typed params; LocaleLike keeps ru structurally in sync with en at compile time
const en = {
	welcome: "welcome to the yaebal shop. use /catalog, /deal, /cart, /checkout.",
	cart_empty: "your cart is empty.",
	cart_title: "cart",
	added: "added {name}.",
	removed: "removed {name}.",
	locale: "language switched to english.",
	limited: "slow down a bit. the shop is rate-limited per user.",
	items: { one: "{n} item", other: "{n} items" },
} as const satisfies Dict;

const ru = {
	welcome: "добро пожаловать в yaebal shop. используй /catalog, /deal, /cart, /checkout.",
	cart_empty: "корзина пустая.",
	cart_title: "корзина",
	added: "добавлено: {name}.",
	removed: "удалено: {name}.",
	locale: "язык переключен на русский.",
	limited: "помедленнее. магазин ограничивает частоту на пользователя.",
	items: { one: "{n} товар", few: "{n} товара", many: "{n} товаров", other: "{n} товара" },
} as const satisfies LocaleLike<typeof en>;

const locales = { en, ru };

// enum `op` costs one char on the wire and narrows to "add" | "remove"
const cartAction = callbackData("cart", { op: field.enum(["add", "remove"]), id: Number });
// menu-only entries: the handlers live on the bot chain below, the / menu (with
// per-locale descriptions) comes from this registry
const menu = commands()
	.add("start", { default: "open the shop", ru: "открыть магазин" })
	.add("catalog", { default: "browse products", ru: "каталог товаров" })
	.add("deal", { default: "show the featured deal", ru: "предложение дня" })
	.add("cart", { default: "show cart", ru: "показать корзину" })
	.add("checkout", { default: "fake checkout", ru: "оформить заказ" })
	.add("lang", { default: "toggle language", ru: "переключить язык" })
	.add("clear", { default: "empty cart", ru: "очистить корзину" })
	.add("help", { default: "show commands", ru: "список команд" });

const catalog = pagination<Product>({
	id: "shop",
	pageSize: 4,
	source: () => products,
	header: (info) => `catalog page ${info.page + 1}/${info.pages}`,
	line: (item) => `#${item.id} ${item.name} - $${item.price} (${item.tag})`,
	// each product is also a tappable button — selecting opens its deal card
	item: (p) => ({ label: `#${p.id} ${p.name}`, id: p.id }),
	onSelect: (ctx, sel) =>
		sendDeal(
			ctx,
			products.find((p) => p.id === sel.id),
		),
	columns: 2,
});

const bot = createBot(token)
	.install(
		ratelimiter({
			limit: 8,
			windowMs: 2_000,
			onLimit: (ctx) => ctx.reply("slow down a bit. the shop is rate-limited per user."),
		}),
	)
	.install(session<CartSession>({ initial: () => ({ items: {} }) }))
	.install(i18n({ defaultLocale: "en", locales }))
	.install(catalog.plugin())
	.install(menu.plugin())
	.command("start", (ctx) =>
		ctx.reply(ctx.t("welcome"), {
			reply_markup: new InlineKeyboard()
				.text("catalog", "open:catalog")
				.text("deal", "open:deal")
				.row()
				.text("cart", "open:cart")
				.text("language", "open:lang")
				.build(),
		}),
	)
	.command("catalog", (ctx) => catalog.send(ctx))
	.command("deal", (ctx) => sendDeal(ctx, products[0]))
	.command("cart", (ctx) => ctx.reply(renderCart(ctx.session, ctx.t)))
	.command("checkout", (ctx) => {
		const lines = renderCart(ctx.session, ctx.t);
		if (lines === ctx.t("cart_empty")) return ctx.reply(lines);

		return ctx.reply(`${lines}\n\ncheckout is mocked: no money moved, only types.`);
	})
	.command("lang", async (ctx) => {
		await ctx.changeLanguage(ctx.locale === "ru" ? "en" : "ru");
		return ctx.reply(ctx.t("locale"));
	})
	.command("clear", (ctx) => {
		ctx.session.items = {};
		return ctx.reply("cart cleared.");
	})
	.filter(and(filters.isPrivate, filters.command("help")), (ctx) =>
		ctx.send(
			html`<b>commerce suite commands</b>\n${menu
				.list({ languageCode: ctx.locale })
				.map((c) => `/${c.command} - ${c.description}`)
				.join("\n")}`,
		),
	)
	.callbackQuery(/^open:/, async (ctx) => {
		const action = ctx.callbackQuery.data?.slice("open:".length);
		await ctx.answer();

		if (action === "catalog") return catalog.send(ctx);
		if (action === "deal") return sendDeal(ctx, products[0]);
		if (action === "cart") return ctx.send(renderCart(ctx.session, ctx.t));
		if (action === "lang") {
			await ctx.changeLanguage(ctx.locale === "ru" ? "en" : "ru");
			return ctx.send(ctx.t("locale"));
		}
	})
	// pass the namespace itself: the payload is validated + decoded to `ctx.queryData`,
	// and this handler only runs on a clean unpack
	.callbackQuery(cartAction, async (ctx) => {
		const product = products.find((item) => item.id === ctx.queryData.id);
		if (!product) return ctx.answer("unknown product");

		if (ctx.queryData.op === "add") {
			ctx.session.items[product.id] = (ctx.session.items[product.id] ?? 0) + 1;
			await ctx.answer(ctx.t("added", { name: product.name }));
		} else {
			const next = Math.max(0, (ctx.session.items[product.id] ?? 0) - 1);
			if (next === 0) delete ctx.session.items[product.id];
			else ctx.session.items[product.id] = next;
			await ctx.answer(ctx.t("removed", { name: product.name }));
		}

		return ctx.send(renderCart(ctx.session, ctx.t));
	})
	.hears(/^#?(\d+)$/, (ctx) => {
		const id = Number(ctx.match[1]);
		return sendDeal(
			ctx,
			products.find((item) => item.id === id),
		);
	})
	.on("message:text", (ctx) => ctx.reply("send /catalog or a product id like 3."))
	.onStart(async (info) => {
		// diff-aware: pushes the default + ru menus only when they changed
		await menu.sync(bot.api).catch(() => {});
		console.log(`@${info.username} commerce suite is live`);
	});

function renderCart(session: CartSession, t: TFn<typeof en>): string {
	const rows = Object.entries(session.items)
		.map(([id, qty]) => ({ product: products.find((item) => item.id === Number(id)), qty }))
		.filter(
			(row): row is { product: Product; qty: number } => row.product !== undefined && row.qty > 0,
		);

	if (rows.length === 0) return t("cart_empty");

	const totalQty = rows.reduce((sum, row) => sum + row.qty, 0);
	const total = rows.reduce((sum, row) => sum + row.product.price * row.qty, 0);

	return [
		`${t("cart_title")} - ${t("items", { n: totalQty })}`,
		...rows.map((row) => `${row.qty} x ${row.product.name} - $${row.product.price * row.qty}`),
		`total: $${total}`,
	].join("\n");
}

function sendDeal(ctx: Context, product: Product | undefined) {
	if (!product) return ctx.reply("unknown product id.");

	return ctx.reply(`${product.name}\nprice: $${product.price}\ntag: ${product.tag}`, {
		reply_markup: new InlineKeyboard()
			.text("add", cartAction.pack({ op: "add", id: product.id }))
			.text("remove", cartAction.pack({ op: "remove", id: product.id }))
			.build(),
	});
}

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { Bot, blockquote, bold, code, format, italic, join } from "@yaebal/core";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/core-echo/.env first (copy .env.example)");
	process.exit(1);
}

// bare @yaebal/core: middleware engine, filter queries, ctx.send/reply, raw typed api client.
// no generated contexts here — ctx.react()/ctx.answer() sugar needs @yaebal/contexts (or yaebal).
const bot = new Bot(token, { allowedUpdates: ["message"] })
	.derive(() => ({ receivedAt: new Date() }))
	.command("start", (ctx) =>
		// helpers nest (bold(italic(…))) and join() keeps entities where [].join() would drop them
		ctx.send(
			format`${bold("core echo")} — a bot on ${bold(italic("bare"))} @yaebal/core.
send any text and it comes back; try ${join(["/me", "/react", "/quote"], (cmd) => code(cmd))}.`,
		),
	)
	.command("quote", (ctx) =>
		// a format result is accepted by every api method — the client splits it into
		// text + entities anywhere the schema allows formatted text, nested params included
		ctx.api.sendMessage({
			chat_id: ctx.chat!.id,
			text: format`${blockquote("sent through raw api.sendMessage — still no parse_mode")}`,
		}),
	)
	.command("me", async (ctx) => {
		const me = await ctx.api.getMe();
		return ctx.reply(`i am @${me.username} (id ${me.id})`);
	})
	.command("react", async (ctx) => {
		// core has no ctx.react() — that shortcut is generated in @yaebal/contexts.
		// the raw passthrough takes any Bot API method, current or future.
		await ctx.api.call("setMessageReaction", {
			chat_id: ctx.chat?.id,
			message_id: ctx.message?.message_id,
			reaction: [{ type: "emoji", emoji: "👍" }],
		});
	})
	.on("message:text", (ctx) => ctx.reply(`echo at ${ctx.receivedAt.toISOString()}: ${ctx.text}`))
	.onStart((info) => console.log(`@${info.username} core echo is live`));

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { cron, cronAdmin } from "@yaebal/cron";
import { fileStorage } from "@yaebal/sklad/file";
import { createBot } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/cron/.env first (copy .env.example)");
	process.exit(1);
}

// set ADMIN_ID in .env to your telegram user id to gate /cron; otherwise everyone can use it
// (fine for this demo, but pass a real allow-list/role check in production).
const adminId = process.env.ADMIN_ID ? Number(process.env.ADMIN_ID) : undefined;

// persists each job's lastRunAt to a JSON file — restart the bot and "digest" still knows
// whether it missed its 09:00 run while the process was down. any @yaebal/sklad adapter works
// here (MemoryStorage, redisStorage, sqliteStorage, kvStorage) — fileStorage is the
// zero-infrastructure choice for a demo like this one.
const store = fileStorage<{ lastRunAt: number }>("./data/cron-state.json");

let syncAttempts = 0;

const bot = createBot(token)
	.install(
		cron({
			tz: "Europe/Moscow", // default zone for every job below; per-job `tz` overrides it
			store,
			onEvent: (event) => console.log(`[cron] ${event.type}`, event),
			jobs: {
				// fires every 10s — watch it tick in the terminal without touching any commands
				heartbeat: {
					schedule: 10_000,
					task: (ctx) => console.log(`[heartbeat] tick #${ctx.run}`),
				},

				// intentionally flaky, to show retries + backoff + a cooperative timeout in action.
				// overlap: "wait" means a tick that arrives mid-retry queues instead of piling up.
				"flaky-sync": {
					schedule: 15_000,
					overlap: "wait",
					retries: 2,
					retryDelayMs: (attempt) => attempt * 500, // 500ms, then 1000ms
					timeoutMs: 3_000,
					task: async (ctx) => {
						console.log(
							`[flaky-sync] run ${ctx.run}, attempt ${ctx.attempt} (total attempts: ${++syncAttempts})`,
						);
						if (Math.random() < 0.5) throw new Error("upstream hiccup");
					},
					onError: (error) => console.error("[flaky-sync] gave up:", (error as Error).message),
				},

				// a real "send a report" job: cron expression (in Moscow time), catches up on a
				// missed run at startup (see `store` above), and is also triggerable on demand
				// below via /run-digest — respecting whatever's already in flight.
				digest: {
					schedule: "0 9 * * *", // 09:00 Europe/Moscow
					catchUp: true,
					retries: 1,
					task: async (ctx) => {
						console.log(
							`[digest] sending (scheduled for ${new Date(ctx.scheduledFor).toISOString()})`,
						);
					},
				},
			},
		}),
	)
	// a telegram-native ops surface for every job above:
	// /cron | /cron run <name> | /cron pause|resume <name> | /cron next <name>
	.install(cronAdmin({ isAdmin: (ctx) => adminId === undefined || ctx.from?.id === adminId }));

bot.command("start", (ctx) =>
	ctx.reply(
		[
			"this bot demos @yaebal/cron. try:",
			"/run-digest — trigger the digest job now, bypassing its schedule",
			"/state — every job's current state (runs, failures, next/last run)",
			"/cron — the cronAdmin ops surface (admin command; open unless ADMIN_ID is set)",
			"",
			"heartbeat ticks every 10s and flaky-sync (which fails ~50% of the time, retrying with",
			"backoff) runs every 15s — watch the terminal to see them fire on their own.",
		].join("\n"),
	),
);

// the plugin decorates ctx.cron — any handler can reach trigger/pause/resume/states/nextRuns
// without a separate import.
bot.command("run-digest", async (ctx) => {
	const outcome = await ctx.cron.trigger("digest"); // "ran" | "skipped" — never disturbs the schedule
	await ctx.reply(`digest: ${outcome}`);
});

bot.command("state", async (ctx) => {
	const lines = ctx.cron.states().map((state) => {
		const next = state.nextRunAt ? new Date(state.nextRunAt).toISOString() : "—";
		return `${state.name}: runs=${state.runs} failures=${state.failures} next=${next}`;
	});
	await ctx.reply(lines.join("\n") || "(no jobs)");
});

bot.start();

import { conversation, createConversation } from "@yaebal/conversation";
import { back, button, type DialogDef, dialogs, switchTo } from "@yaebal/morda";
import { prompt } from "@yaebal/prompt";
import { ask, defineScene, scenes } from "@yaebal/scenes";
import { type Context, createBot, session } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/dialog-quest/.env first (copy .env.example)");
	process.exit(1);
}

interface Profile {
	name?: string;
	klass?: string;
	goal?: string;
	darkMode: boolean;
	tickets: string[];
}

// waitFor narrows to a fresh text message, so topic.text is a plain string — no "?? fallback"
// needed. /cancel needs no special-casing here either: passCommands (on by default) routes it
// straight to the global "cancel" command below, which leaves the conversation for us.
const support = createConversation(async (cv, ctx) => {
	await ctx.send("support mode: describe the problem, or send /cancel.");
	const topic = await cv.waitFor("message:text");

	const urgency = await cv.form.choice({
		question: "how urgent is it: low, normal, or fire?",
		choices: ["low", "normal", "fire"] as const,
		invalid: "pick one: low, normal, or fire.",
	});

	await ctx.send(`ticket queued: ${topic.text} / urgency ${urgency}`);
});

// answers collect in the typed ctx.scene.state bag (no external map needed) and
// land in ctx.session only on finish. the def's context requires the session
// plugin, so installing scenes before session would be a compile error. a global
// /cancel keeps working mid-wizard — commands bypass active scenes by default.
const questScene = defineScene<
	Context & { session: Profile },
	{ name: string; klass: string; goal: string }
>({
	steps: [
		ask("name", { question: "quest wizard: what is your name? send /cancel to leave." }),
		ask("klass", {
			question: (ctx) => `nice, ${ctx.scene.state.name}. choose a class: builder, mage, runner.`,
			parse: (text) => {
				const klass = text.trim().toLowerCase();
				return ["builder", "mage", "runner"].includes(klass) ? klass : undefined;
			},
			invalid: "builder, mage or runner — pick one.",
		}),
		ask("goal", {
			question: (ctx) => `class locked: ${ctx.scene.state.klass}. what is your launch goal?`,
		}),
	],
	onLeave: async (ctx, info) => {
		if (info.cancelled) return ctx.reply("quest cancelled.");
		if (info.reason !== "finish") return;

		Object.assign(ctx.session, ctx.scene.state);
		return ctx.reply(
			`quest saved: ${ctx.scene.state.goal}. open /profile to see the current state.`,
		);
	},
});

const dialogsByChat = new Map<number, Profile>();

const cockpit: DialogDef = {
	main: (ctx) => ({
		text: `cockpit\nprofile: ${profileLine(getProfile(ctx.chat?.id))}`,
		keyboard: [
			[switchTo("profile", "profile"), switchTo("settings", "settings")],
			[
				button("new quest", {
					id: "quest",
					onClick: (c) => c.send("run /quest to start the scene wizard."),
				}),
				button("support", {
					id: "support",
					onClick: (c) => c.send("run /support to start the coroutine flow."),
				}),
			],
		],
	}),
	profile: (ctx) => ({
		text: `profile\n${profileLine(getProfile(ctx.chat?.id))}`,
		keyboard: [[back("back")]],
	}),
	settings: (ctx) => ({
		text: `settings\ndark mode: ${getProfile(ctx.chat?.id).darkMode ? "on" : "off"}`,
		keyboard: [
			[
				button("toggle dark", {
					id: "dark",
					onClick: async (c) => {
						const profile = getProfile(c.chat?.id);
						profile.darkMode = !profile.darkMode;
						await c.dialog.rerender();
					},
				}),
			],
			[back("back")],
		],
	}),
};

const bot = createBot(token)
	.install(session<Profile>({ initial: () => ({ darkMode: false, tickets: [] }) }))
	.derive((ctx) => {
		if (ctx.chat?.id !== undefined) dialogsByChat.set(ctx.chat.id, ctx.session);
		return {};
	})
	.install(scenes({ quest: questScene }))
	.install(prompt())
	.install(conversation({ support }))
	.install(dialogs(cockpit))
	.command("start", (ctx) => ctx.dialog.start("main"))
	.command("quest", (ctx) => ctx.scene.enter("quest"))
	.command("support", (ctx) => {
		ctx.conversation.enter("support");
		return ctx.reply("support flow started.");
	})
	.command("rename", (ctx) =>
		ctx.prompt("new display name?", (answer) => {
			const next = answer as typeof ctx;
			next.session.name = answer.text;
			return answer.reply(`saved name: ${answer.text}`);
		}),
	)
	.command("profile", (ctx) => ctx.reply(profileLine(ctx.session)))
	.command("cancel", async (ctx) => {
		// reachable mid-wizard: commands pass through both an active scene and an active
		// conversation by default (scenes' passCommands, conversation's passCommands)
		if (ctx.scene.active) return ctx.scene.leave({ cancelled: true });
		if (ctx.conversation.active) await ctx.conversation.leave();
		return ctx.reply("active flow cancelled.");
	})
	.on("message:text", (ctx) => ctx.reply("open /start, /quest, /support or /rename."))
	.onStart(async (info) => {
		await bot.api
			.call("setMyCommands", {
				commands: [
					{ command: "start", description: "open cockpit" },
					{ command: "quest", description: "start quest wizard" },
					{ command: "support", description: "start support flow" },
					{ command: "rename", description: "save display name" },
					{ command: "profile", description: "show profile" },
					{ command: "cancel", description: "leave active flow" },
				],
			})
			.catch(() => {});
		console.log(`@${info.username} dialog quest is live`);
	});
function getProfile(chatId: number | undefined): Profile {
	if (chatId === undefined) return { darkMode: false, tickets: [] };
	let profile = dialogsByChat.get(chatId);
	if (!profile) {
		profile = { darkMode: false, tickets: [] };
		dialogsByChat.set(chatId, profile);
	}
	return profile;
}

function profileLine(profile: Profile): string {
	return [
		`name: ${profile.name ?? "anonymous"}`,
		`class: ${profile.klass ?? "none"}`,
		`goal: ${profile.goal ?? "none"}`,
		`dark mode: ${profile.darkMode ? "on" : "off"}`,
	].join("\n");
}

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { commands } from "@yaebal/commands";
import { type EphemeralControl, ephemeral, wrapEphemeralMessage } from "@yaebal/ephemeral";
import { type Context, createBot, InlineKeyboard } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/ephemeral/.env first (copy .env.example)");
	process.exit(1);
}

// the registry's handlers see ctx.replyEphemeral / ctx.sendEphemeral because the
// ephemeral() plugin is installed before cmd.plugin() below
type BotContext = Context & EphemeralControl;

const rollKeyboard = () => new InlineKeyboard().text("reroll", "reroll").text("dismiss", "dismiss");

const cmd = commands<BotContext>()
	// ephemeral(): the menu entry carries is_ephemeral — in groups telegram shows the
	// /roll invocation only to its sender, and the answer below stays private too
	.ephemeral("roll", "roll a die only you can see", async (ctx) => {
		// in a group: a real ephemeral message. in a private chat: a normal message
		// (already visible to just this user) behind the exact same handle.
		const msg = await ctx.replyEphemeral("rolling…");
		await msg.edit(`🎲 you rolled a ${1 + Math.floor(Math.random() * 6)}`, {
			reply_markup: rollKeyboard(),
		});
	})
	.ephemeral("me", "who telegram thinks you are", (ctx) =>
		ctx.replyEphemeral(
			[
				`id: ${ctx.from?.id}`,
				`name: ${ctx.from?.first_name}`,
				`premium: ${ctx.from?.is_premium ? "yes" : "no"}`,
			].join("\n"),
		),
	)
	// a normal command for contrast — this one lands in the group history for everyone
	.add("about", "what this bot demonstrates", (ctx) =>
		ctx.reply(
			[
				"a focused tour of @yaebal/ephemeral + @yaebal/commands:",
				"/roll and /me answer so only you see it (add me to a group to see the",
				"difference — in this private chat the fallback sends a normal message).",
				"see examples/ephemeral/src/index.ts.",
			].join("\n"),
		),
	);

const bot = createBot(token)
	.install(ephemeral({ onExpired: "ignore" }))
	.install(cmd.plugin())
	.on("callback_query", async (ctx) => {
		await ctx.answerCallbackQuery();

		// the buttons live on an ephemeral message — rebuild a handle from the
		// callback's message payload and keep editing it in place
		const message = ctx.callbackQuery.message;
		if (!message || !("ephemeral_message_id" in message)) return;
		if (message.ephemeral_message_id === undefined) return;

		const msg = wrapEphemeralMessage(ctx.api, message, { onExpired: "ignore" });
		if (ctx.callbackQuery.data === "dismiss") {
			await msg.delete(); // idempotent: false (not a crash) if it already expired
			return;
		}
		if (ctx.callbackQuery.data === "reroll") {
			await msg.edit(`🎲 you rolled a ${1 + Math.floor(Math.random() * 6)}`, {
				reply_markup: rollKeyboard(),
			});
		}
	})
	.onStart(async (info) => {
		// pushes is_ephemeral flags too — flipping a command to ephemeral repushes its menu
		const result = await cmd.sync(bot.api).catch(() => undefined);
		const status = result
			? `${result.pushed.length} pushed, ${result.skipped.length} unchanged`
			: "sync failed";
		console.log(`@${info.username} ephemeral tour is live — menus: ${status}`);
	});

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { envProvider, featureFlags, flagsAdmin, whenFlag } from "@yaebal/feature-flags";
import { createBot } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/feature-flags/.env first (copy .env.example)");
	process.exit(1);
}

// set ADMIN_ID in .env to your telegram user id to unlock /flags; otherwise everyone can use it
// (fine for this demo, but pass a real allow-list/role check in production).
const adminId = process.env.ADMIN_ID ? Number(process.env.ADMIN_ID) : undefined;

const bot = createBot(token)
	.install(
		featureFlags({
			flags: {
				// a plain percentage rollout — 25% of users see it, deterministically
				"new-ui": { default: false, rules: [{ percentage: 25 }] },

				// default on for everyone, except a kill-switched cohort (value: false)
				"legacy-mode": { default: true, rules: [{ userIds: [666], value: false }] },

				// only announced in group chats
				"group-announce": { default: false, rules: [{ chatTypes: ["group", "supergroup"] }] },

				// a multivariate flag: three checkout flows, weighted
				checkout: {
					default: "control",
					variants: [
						{ value: "control", weight: 50 },
						{ value: "v2", weight: 30 },
						{ value: "v3", weight: 20 },
					],
				},
			},
			// process.env.FLAG_NEW_UI, if set, overrides the local catalog for "new-ui" — try
			// `FLAG_NEW_UI=true pnpm --filter @yaebal/example-feature-flags dev`
			provider: envProvider(),
			onEvaluate: (event) =>
				console.log(`[flags] ${event.key} -> ${JSON.stringify(event.value)} (${event.source})`),
		}),
	)
	// an isolated branch: only reachable while "new-ui" is on for the caller, regardless of
	// where in the chain it's installed or what's registered around it
	.install(
		whenFlag("new-ui", (branch) =>
			branch.command("beta", (ctx) => ctx.reply("you're in the new-ui beta — thanks for testing!")),
		),
	)
	// telegram-native admin surface: /flags, /flags set <key> <value>, /flags clear <key>
	.install(
		flagsAdmin({
			isAdmin: (ctx) => adminId === undefined || ctx.from?.id === adminId,
		}),
	);

bot.command("start", (ctx) =>
	ctx.reply(
		[
			"this bot demos @yaebal/feature-flags. try:",
			"/feature — is new-ui on for you? (25% rollout)",
			"/enable — force new-ui on for yourself only",
			"/beta — only answers while new-ui is on for you",
			"/checkout — which checkout variant you're bucketed into",
			"/promote — force everyone onto the v2 checkout (global override)",
			"/announce — only answers in a group/supergroup chat",
			"/flags — list every flag (admin command; open unless ADMIN_ID is set)",
		].join("\n"),
	),
);

bot.command("feature", async (ctx) => {
	const on = await ctx.flags.isEnabled("new-ui");
	await ctx.reply(`new-ui: ${on ? "on" : "off"}`);
});

bot.command("enable", async (ctx) => {
	await ctx.flags.setOverride("new-ui", true);
	await ctx.reply("new-ui enabled for you — try /feature again, then /beta");
});

bot.command("checkout", async (ctx) => {
	const variant = await ctx.flags.getVariant("checkout");
	await ctx.reply(`checkout: ${variant}`);
});

bot.command("promote", async (ctx) => {
	// forces every bucket at once, independent of any per-user override — an emergency-safe
	// rollout lever, auto-expiring after an hour so a bad promotion can't linger forever
	await ctx.flags.setGlobalOverride("checkout", "v2", { ttl: 60 * 60 * 1000 });
	await ctx.reply("checkout: v2 promoted for everyone (expires in 1h)");
});

bot.command("announce", async (ctx) => {
	const on = await ctx.flags.isEnabled("group-announce");
	await ctx.reply(
		on ? "📣 group announcement is live here" : "nothing to announce (not a group chat)",
	);
});

bot.start();

import {
	botHasPermission,
	guardOr,
	hasPermission,
	isAdmin,
	isAnonymousAdmin,
	isOwner,
	membership,
} from "@yaebal/guards";
import { and, createBot, filters } from "yaebal";

// a focused bot that shows @yaebal/guards: cached membership lookups, answering a denial
// instead of dropping it, and telegram's anonymous-admin/owner edge case.
//
//   pnpm --filter @yaebal/example-guards dev   (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/guards/.env first (copy .env.example)");
	process.exit(1);
}

const bot = createBot(token).install(
	membership({
		ttl: 60_000,
		onEvent: (event) => console.log(`[membership cache] ${event.type} ${event.key}`),
	}),
);

bot.command("start", (ctx) =>
	ctx.reply(
		"This bot uses @yaebal/guards. Try /ban (admin-only, cached), /mute (denial gets a " +
			"reply), /pin (checks the bot's own permission), and /whoami (dumps every guard's " +
			"verdict for you).",
	),
);

// the safe pattern: getChatMember only runs for an actual /ban, not for every message —
// membership() then caches that lookup for 60s per (chat, user).
bot.filter(and(filters.command("ban"), isAdmin), (ctx) =>
	ctx.reply(`banned by ${ctx.from?.first_name ?? "someone"} (not really — this is a demo)`),
);

// guardOr answers a denial instead of silently dropping the update, unlike bare bot.guard().
bot
	.use(guardOr(isAdmin, (ctx) => ctx.reply("admins only.")))
	.command("mute", (ctx) => ctx.reply("muted (not really — this is a demo)"));

// checking the bot's *own* standing before an action that needs it.
bot.command("pin", async (ctx) => {
	if (!(await botHasPermission("can_pin_messages")(ctx))) {
		await ctx.reply("I don't have permission to pin messages here.");
		return;
	}

	await ctx.reply("I could pin messages here (not actually pinning — this is a demo).");
});

// dump every guard's verdict for the caller — including telegram's anonymous-admin/owner
// case, where isAdmin passes without an api call but isOwner denies (telegram never says
// which one an anonymous poster actually is).
bot.command("whoami", async (ctx) => {
	const [admin, owner, restrictor, anonymous] = await Promise.all([
		isAdmin(ctx),
		isOwner(ctx),
		hasPermission("can_restrict_members")(ctx),
		Promise.resolve(isAnonymousAdmin(ctx)),
	]);

	await ctx.reply(
		[
			`anonymous poster: ${anonymous}`,
			`isAdmin: ${admin}`,
			`isOwner: ${owner}`,
			`hasPermission("can_restrict_members"): ${restrictor}`,
		].join("\n"),
	);
});

bot.start();

import { contextFor } from "@yaebal/contexts";
import { Bot } from "@yaebal/core";
import { html } from "@yaebal/fmt";
import type { InlineQueryResult } from "@yaebal/types";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/inline-search/.env first (copy .env.example)");
	process.exit(1);
}

const bot = new Bot(token, { allowedUpdates: ["message", "inline_query", "chosen_inline_result"] })
	.command("start", (ctx) =>
		ctx.send(html`<b>inline search</b>\nopen any chat and type <code>@your_bot query</code>.`),
	)
	.on("inline_query", async (ctx) => {
		// bare core has no per-update contexts — @yaebal/contexts is a separate install on
		// top of it. wrap the raw update once and the generated shortcuts appear:
		// .answer() fills inline_query_id itself, payload fields are typed.
		const inline = contextFor("inline_query", ctx.api, ctx.update);

		const query = inline.query.trim() || "yaebal";
		const offset = Number(inline.offset || 0);
		const results = Array.from({ length: 5 }, (_, index): InlineQueryResult => {
			const id = offset + index + 1;
			const title = `${query} result ${id}`;

			return {
				type: "article",
				id: String(id),
				title,
				description: "generated by examples/inline-search",
				input_message_content: {
					message_text: `inline result: ${title}`,
				},
			};
		});

		await inline.answer(results, {
			cache_time: 0,
			is_personal: true,
			next_offset: String(offset + results.length),
			button: { text: "open bot", start_parameter: "inline" },
		});
	})
	.on("chosen_inline_result", (ctx) => {
		const chosen = contextFor("chosen_inline_result", ctx.api, ctx.update);

		console.log("chosen inline result", {
			resultId: chosen.result_id,
			from: chosen.senderId,
			query: chosen.query,
		});
	})
	.onStart((info) => console.log(`@${info.username} inline search is live`));

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { createBot, InlineKeyboard, Keyboard } from "yaebal";

// a tour of every @yaebal/keyboard feature. each command builds one kind of markup.
//
//   pnpm --filter @yaebal/example-keyboard dev   (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/keyboard/.env first (copy .env.example)");
	process.exit(1);
}

// the command menu telegram shows in the "/" picker — registered on start
const COMMANDS = [
	{ command: "start", description: "text/style/url/row — the basics" },
	{ command: "gallery", description: "every remaining inline button type" },
	{ command: "grid", description: "buttons from an array — add() + columns()" },
	{ command: "contact", description: "contact/location/poll/web app (reply keyboard)" },
	{ command: "profile", description: "request user/chat/managed bot (reply keyboard)" },
	{ command: "hide", description: "Keyboard.remove()" },
	{ command: "ask", description: "Keyboard.forceReply()" },
	{ command: "help", description: "list every command" },
];

// items for the /grid demo — anything can be mapped into buttons this way
const FRUITS = ["apple", "banana", "cherry", "date", "fig", "grape"];

// the exact prompt /ask sends — used to recognize the reply to it
const ASK_PROMPT = "what's your name?";

const bot = createBot(token)
	// text, style(), url(), row() — the basics. reply_markup takes the builder
	// itself here: InlineKeyboard implements toJSON(), and Api stringifies
	// reply_markup, so the trailing .build() below is optional (both work).
	.command("start", (ctx) =>
		ctx.reply("👋 welcome — try /gallery, /grid, /contact, /profile, /hide, /ask or /help.", {
			reply_markup: new InlineKeyboard()
				.text("👍 like", "vote:up")
				.text("👎 dislike", "vote:down")
				.style("danger") // styles the button just added — "👎 dislike"
				.row()
				.url("⭐ star it on github", "https://github.com/neverlane/yaebal"),
		}),
	)
	.callbackQuery(/^vote:(up|down)$/, async (ctx) => {
		const liked = ctx.callbackQuery.data === "vote:up";
		await ctx.answer(liked ? "thanks! 👍" : "noted 👎");
	})

	// every inline button type that's safe to send in a plain message.
	// .pay()/.game()/.icon() are demoed separately below — telegram rejects them
	// outside their specific requirements (see the comment further down).
	.command("gallery", (ctx) => {
		const kb = new InlineKeyboard()
			.webApp("open web app", "https://core.telegram.org/bots/webapps")
			.row()
			.login("log in", "https://core.telegram.org/widgets/login") // needs a domain linked via @BotFather
			.row()
			.switchInline("share in a chat", "yaebal")
			.row()
			.switchInlineCurrentChat("insert here", "yaebal")
			.row()
			.switchInlineChosenChat("share in a group", { allow_group_chats: true })
			.row()
			.copyText("copy install command", "pnpm add @yaebal/keyboard")
			.build();

		// .pay()/.game() are only valid as the first button of the first row, and
		// only inside an invoice/game message. .icon() needs a *numeric* custom
		// emoji id (not a literal emoji), and only renders for bots that bought a
		// Fragment username or whose owner has Telegram Premium — building all
		// three here just to show the api, not sending them.
		console.log("pay button:", JSON.stringify(new InlineKeyboard().pay("5 ⭐").build()));
		console.log("game button:", JSON.stringify(new InlineKeyboard().game("play").build()));
		console.log(
			"icon button:",
			JSON.stringify(
				new InlineKeyboard().text("starred", "noop").icon("5368324170671202286").build(),
			),
		);

		return ctx.reply(
			"every inline button type (minus pay/game/icon — see the bot's console log):",
			{
				reply_markup: kb,
			},
		);
	})

	// buttons built from an array: add() + the static, instance-free builders,
	// wrapped into rows of 3 by columns().
	.command("grid", (ctx) =>
		ctx.reply("pick a fruit:", {
			reply_markup: new InlineKeyboard()
				.columns(3)
				.add(...FRUITS.map((fruit) => InlineKeyboard.text(fruit, `pick:${fruit}`)))
				.build(),
		}),
	)
	.callbackQuery(/^pick:/, async (ctx) => {
		const fruit = ctx.callbackQuery.data?.slice("pick:".length);
		await ctx.answer(`you picked ${fruit} 🍽️`);
	})

	// reply keyboard: requestContact/requestLocation/requestPoll/webApp, resized + oneTime.
	.command("contact", (ctx) =>
		ctx.reply("share something with the bot:", {
			reply_markup: new Keyboard()
				.requestContact("📱 share phone")
				.requestLocation("📍 share location")
				.row()
				.requestPoll("📊 create a poll", "quiz")
				.webApp("🌐 open web app", "https://core.telegram.org/bots/webapps")
				.resized()
				.oneTime()
				.build(),
		}),
	)
	.on("message:contact", (ctx) => ctx.reply(`got your contact: ${ctx.contact?.phone_number}`))
	.on("message:location", (ctx) =>
		ctx.reply(`got your location: ${ctx.location?.latitude}, ${ctx.location?.longitude}`),
	)
	.on("message:poll", (ctx) => ctx.reply(`got your poll: "${ctx.poll?.question}"`))

	// reply keyboard: requestUsers/requestChat/requestManagedBot, persistent +
	// placeholder + selective. requestId only needs to be unique within this keyboard.
	.command("profile", (ctx) =>
		ctx.reply("pick one:", {
			reply_markup: new Keyboard()
				.requestUsers("👤 pick a user", 1, { max_quantity: 1, user_is_bot: false })
				.row()
				.requestChat("📢 pick a channel", 2, /* isChannel */ true, { request_title: true })
				.row()
				.requestChat("👥 pick a group", 3, /* isChannel */ false)
				.row()
				.requestManagedBot("🤖 create a bot for me", 4, { suggested_name: "My Shop Bot" })
				.persistent()
				.placeholder("pick something above")
				.selective()
				.build(),
		}),
	)
	.on("message:users_shared", (ctx) => {
		const shared = ctx.users_shared;
		return ctx.reply(`request #${shared?.request_id}: got ${shared?.users.length} user(s)`);
	})
	.on("message:chat_shared", (ctx) => {
		const shared = ctx.chat_shared;
		return ctx.reply(`request #${shared?.request_id}: got chat ${shared?.chat_id}`);
	})
	.on("message:managed_bot_created", (ctx) => {
		const bot_ = ctx.managed_bot_created?.bot;
		return ctx.reply(`created @${bot_?.username} — fetch its token with getManagedBotToken`);
	})
	// same event, delivered as its own update instead of a message field
	.on("managed_bot", (ctx) => {
		const updated = ctx.update.managed_bot;
		console.log(`managed_bot update: @${updated?.bot.username}, owner ${updated?.user.id}`);
	})

	// Keyboard.remove() — static, no builder instance needed
	.command("hide", (ctx) => ctx.reply("hiding the keyboard.", { reply_markup: Keyboard.remove() }))

	// Keyboard.forceReply() — static, and a matching handler for the round trip
	.command("ask", (ctx) =>
		ctx.reply(ASK_PROMPT, {
			reply_markup: Keyboard.forceReply({ input_field_placeholder: "your name" }),
		}),
	)
	.on("message:text", (ctx, next) => {
		if (ctx.reply_to_message?.text !== ASK_PROMPT) return next();
		return ctx.reply(`nice to meet you, ${ctx.text}! 🎉`);
	})

	.command("help", (ctx) =>
		ctx.reply(COMMANDS.map((c) => `/${c.command} — ${c.description}`).join("\n")),
	)
	// anything else: echo it back
	.on("message:text", (ctx) => ctx.reply(`you said: ${ctx.text}`))

	.onError((error, ctx) => {
		console.error(`update ${ctx.update.update_id} failed:`, error);
	})
	.onStart(async (info) => {
		// publish the command menu so it shows up in the telegram "/" picker
		await bot.api.call("setMyCommands", { commands: COMMANDS }).catch(() => {});
		console.log(`✨ @${info.username} is live — DM it /start`);
	});

// graceful shutdown
process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

