import { createOnboarding } from "@yaebal/onboarding";
import { bold, createBot, format } from "yaebal";

// a focused tour of @yaebal/onboarding.
//
// pnpm --filter @yaebal/example-onboarding dev (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/onboarding/.env first (copy .env.example)");
	process.exit(1);
}

const welcome = createOnboarding({ id: "welcome", concurrency: "preempt" })
	.step("hello", {
		text: (ctx) =>
			format`hi ${bold(ctx.from?.first_name ?? "there")} - this is a short onboarding tour.`,
		buttons: ["next", "dismiss"],
	})
	.step("features", {
		text: "yaebal onboarding keeps flow state, renders inline buttons, and gives handlers a typed ctx.onboarding.welcome control.",
		buttons: ["next", { text: "jump to commands", goto: "commands" }, "exit"],
	})
	.step("commands", {
		text: "try /status during the tour, /exit to leave it, /disable to opt out, and /tour to restart.",
		buttons: ["next", "exit"],
	})
	.step("done", {
		text: "all set. the flow will now mark itself completed.",
	})
	.onComplete((ctx) => ctx.send("welcome aboard - run /tour any time to see it again."))
	.onExit((ctx, meta) =>
		ctx.send(`left onboarding at ${meta.at || "unknown"}. run /tour to restart.`),
	)
	.onDismiss((ctx) => ctx.send("onboarding dismissed. run /enable if you want to allow it again."))
	.build();

const bot = createBot(token)
	.install(welcome)
	.command("start", async (ctx) => {
		const result = await ctx.onboarding.welcome.start();

		if (result === "already-completed") {
			return ctx.reply("you already completed onboarding. run /tour to force-start it again.");
		}

		if (result === "dismissed" || result === "opted-out") {
			return ctx.reply("onboarding is disabled for you. run /enable, then /tour.");
		}
	})
	.command("tour", (ctx) => ctx.onboarding.welcome.start({ force: true }))
	.command("status", (ctx) => {
		const flow = ctx.onboarding.welcome;
		const active = ctx.onboarding.active;

		return ctx.reply(
			`status=${flow.status}, step=${flow.currentStep ?? "none"}, active=${
				active ? `${active.id}:${active.step}` : "none"
			}`,
		);
	})
	.command("disable", async (ctx) => {
		await ctx.onboarding.disableAll();
		return ctx.reply("all onboarding flows disabled for this scope.");
	})
	.command("enable", async (ctx) => {
		await ctx.onboarding.enableAll();
		await ctx.onboarding.welcome.undismiss();
		return ctx.reply("onboarding enabled. run /tour to start it.");
	})
	.command("exit", (ctx) => ctx.onboarding.welcome.exit())
	.onError((error, ctx) => {
		console.error(`update ${ctx.update.update_id} failed:`, error);
	})
	.onStart(async (info) => {
		await bot.api
			.call("setMyCommands", {
				commands: [
					{ command: "start", description: "start onboarding" },
					{ command: "tour", description: "force-restart onboarding" },
					{ command: "status", description: "show onboarding state" },
					{ command: "disable", description: "disable onboarding" },
					{ command: "enable", description: "enable onboarding" },
					{ command: "exit", description: "exit the active tour" },
				],
			})
			.catch(() => {});

		console.log(`@${info.username} is live - DM it /start`);
	});

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { type PaginationContext, pagination } from "@yaebal/pagination";
import { bold, createBot, field, format, InlineKeyboard, italic } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/pagination/.env first (copy .env.example)");
	process.exit(1);
}

// ── a fake database ──────────────────────────────────────────────────────────
// deterministic data so every run looks the same; "horror" stays empty on
// purpose — it demonstrates the `empty` state.

const GENRES = ["fantasy", "sci-fi", "poetry", "horror"] as const;
type Genre = (typeof GENRES)[number];

interface Book {
	id: number;
	title: string;
	author: string;
	genre: Genre;
	year: number;
}

const FIRST = ["Glass", "Iron", "Silent", "Burning", "Hollow", "Amber", "Paper", "Winter"];
const SECOND = ["Orchard", "Harbor", "Signal", "Meridian", "Lantern", "Archive", "Compass"];
const AUTHORS = ["a. voronova", "d. liet", "m. okafor", "j. calder", "s. anand", "r. holt"];

const books: Book[] = Array.from({ length: 57 }, (_, i) => ({
	id: i + 1,
	title: `${FIRST[i % FIRST.length]} ${SECOND[(i * 3) % SECOND.length]}`,
	author: AUTHORS[i % AUTHORS.length] ?? "unknown",
	genre: GENRES[i % 3] as Genre, // only the first three genres get books
	year: 1970 + ((i * 7) % 55),
}));

// pretend these are SQL queries — the plugin only ever asks for one page
const db = {
	page: (offset: number, limit: number, genre?: Genre) => {
		const rows = genre ? books.filter((b) => b.genre === genre) : books;
		return Promise.resolve(rows.slice(offset, offset + limit));
	},
	count: (genre?: Genre) =>
		Promise.resolve(genre ? books.filter((b) => b.genre === genre).length : books.length),
};

// ── /books — the whole library ───────────────────────────────────────────────
// lazy source with `count`: fetch + count run in parallel, page totals are
// exact, ⏮/⏭ can jump, and the counter button doubles as a refresh.

const library = pagination<Book>({
	id: "lib",
	pageSize: 6,
	source: {
		fetch: ({ offset, limit }) => db.page(offset, limit),
		count: () => db.count(),
	},
	header: (info) => format`${bold("the library")} — ${info.count} books`,
	line: (b, i) => format`${i + 1}. ${bold(b.title)} — ${italic(b.author)}, ${b.year}`,
	counter: true,
	firstLast: true,
	keyboard: (kb) => kb.row().text("✖ close", "lib:close"),
});

// ── /genres — payload-parameterized lists ────────────────────────────────────
// one instance serves every genre: the genre rides the buttons as a typed
// payload, item buttons open a book card, and `button()` navigates back to the
// exact page the reader came from.

const byGenre = pagination({
	id: "genre",
	pageSize: 5,
	payload: { genre: field.enum(GENRES) },
	source: {
		fetch: ({ offset, limit, payload }) => db.page(offset, limit, payload.genre),
		count: (_ctx, payload) => db.count(payload.genre),
	},
	header: (info) => format`${bold(info.payload.genre)} — page ${info.page + 1}/${info.pages}`,
	empty: (info) => `no ${info.payload.genre} books yet.`,
	item: (b) => ({ label: b.title, id: b.id }),
	columns: 1,
	counter: true,
	onSelect: (ctx, sel) => {
		const book = books.find((b) => b.id === sel.id);
		if (book) return showBookCard(ctx, book, sel.page);
	},
});

/** edit the tapped list into a book card; `button()` morphs it back to the same page. */
// the explicit return type breaks the byGenre → onSelect → showBookCard inference cycle
function showBookCard(
	ctx: PaginationContext,
	book: Book,
	page: number,
): Promise<unknown> | undefined {
	const message = ctx.callbackQuery.message;
	const chatId = ctx.chat?.id;
	if (!message || chatId === undefined) return;

	const card = format`${bold(book.title)}
${italic(book.author)}, ${book.year}
genre: ${book.genre}`;

	return ctx.api.call("editMessageText", {
		chat_id: chatId,
		message_id: message.message_id,
		text: card.text,
		entities: card.entities,
		reply_markup: new InlineKeyboard()
			.add(byGenre.button("« back to the list", { page, payload: { genre: book.genre } }))
			.build(),
		...ctx.businessRouting(),
	});
}

// ── /feed — a personal list ──────────────────────────────────────────────────
// lazy source WITHOUT `count`: the plugin probes limit+1 rows per page, so the
// header shows "page N" until the reader hits the end (then the total appears).
// ownership rides the payload — only the requester can page it, even in groups
// and across bot restarts.

const feed = pagination({
	id: "feed",
	pageSize: 4,
	payload: { owner: Number },
	source: {
		fetch: ({ offset, limit, payload }) => {
			// a per-user slice of the library, just to make feeds differ
			const mine = books.filter((b) => b.id % 3 === payload.owner % 3);
			return Promise.resolve(mine.slice(offset, offset + limit));
		},
	},
	line: (b) => `• ${b.title} (${b.year})`,
	labels: { prev: "‹", next: "›" },
	filter: (ctx, payload) => ctx.from?.id === payload.owner,
	denied: "this feed belongs to someone else",
});

// ── the bot ──────────────────────────────────────────────────────────────────

const bot = createBot(token)
	.install(library.plugin())
	.install(byGenre.plugin())
	.install(feed.plugin())
	.command("start", (ctx) =>
		ctx.reply(
			"paginated lists demo:\n" +
				"/books — lazy source + count, ⏮ ◀ N/M ▶ ⏭, refresh via the counter\n" +
				"/genres — one list per payload, tappable items, back-navigation\n" +
				"/feed — endless probing, private to you (try pressing someone else's buttons)",
		),
	)
	.command("books", (ctx) => library.send(ctx))
	.command("genres", (ctx) =>
		ctx.reply("pick a genre — the menu morphs into that list in place:", {
			reply_markup: new InlineKeyboard()
				.columns(2)
				.add(...GENRES.map((genre) => byGenre.button(genre, { payload: { genre } })))
				.build(),
		}),
	)
	.command("feed", (ctx) => {
		const owner = ctx.from?.id;
		if (owner === undefined) return;
		return feed.send(ctx, { payload: { owner } });
	})
	.callbackQuery("lib:close", async (ctx) => {
		const message = ctx.callbackQuery.message;
		if (message && ctx.chat) {
			await ctx.api.call("deleteMessage", { chat_id: ctx.chat.id, message_id: message.message_id });
		}
		await ctx.answerCallbackQuery();
	})
	.onStart((info) => console.log(`@${info.username} pagination demo is live`));

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

import { autoRetry } from "@yaebal/again";
import {
	type CannedResponse,
	handoff,
	MemoryPanelStore,
	type PanelOperator,
	panelHandler,
	recorder,
	recordOutgoing,
} from "@yaebal/panel";
import { serve } from "@yaebal/panel/serve";
import { createBot, type UpdateName } from "yaebal";

// the full tour of @yaebal/panel: live operator dashboard with handoff, multi-operator
// login + audit trail, reply/edit/delete, search, canned responses, export, a typing
// indicator, admin notifications, and media in both directions.
//
//  pnpm --filter @yaebal/example-panel dev
//    needs BOT_TOKEN + PANEL_TOKEN in .env
//    optional: ALICE_TOKEN + BOB_TOKEN instead of PANEL_TOKEN -> multi-operator login
//    optional: ADMIN_CHAT_ID -> your own DM, pinged when a message arrives with no panel open
//  open http://localhost:3000 and log in
const allowedUpdates: UpdateName[] = [
	"message",
	"edited_message",
	"callback_query",
	"message_reaction",
	"message_reaction_count",
	"poll_answer",
	"my_chat_member",
	"chat_member",
];

const bot = createBot(process.env.BOT_TOKEN ?? "", { allowedUpdates });

// in-memory store (lost on restart). swap for a persistent one:
//
//  import { SqlitePanelStore } from "@yaebal/panel/sqlite";
//  const store = new SqlitePanelStore({ path: "./panel.db" }); // fast, FTS5 search, node 22.5+
//
//  import { MemoryStorage } from "@yaebal/sklad"; // or redisStorage/kvStorage/sqliteStorage
//  import { skladPanelStore } from "@yaebal/panel/sklad";
//  const store = skladPanelStore(new MemoryStorage()); // any sklad adapter — redis, kv, edge
const store = new MemoryPanelStore();

autoRetry(bot.api);

// 1. record INCOMING private updates: messages, media, callbacks, reactions and poll answers.
//  widen to group/channel chats with `recorder(store, { chats: "all" })` or a predicate.
bot.install(recorder(store));

// 2. once an operator marks a chat "handled" in the panel, mute the bot's own handlers for
//  it until they release it back to "open" (or archive it) — must come before the handlers
//  registered below, since it's a guard that short-circuits the middleware chain.
bot.install(handoff(store));

// 3. record OUTGOING replies the bot sends from its own handlers (so they appear too).
//  pairs with recordSends:false below to avoid double-logging panel replies.
recordOutgoing(bot.api, store, {
	onError: (error, context) => console.error(`[panel:${context}]`, error),
});

const demoKeyboard = {
	inline_keyboard: [
		[
			{ text: "open media demo", callback_data: "panel:media" },
			{ text: "panel docs", url: "https://yaebal.mom/docs/plugins/panel" },
		],
		[{ text: "record callback event", callback_data: "panel:callback" }],
	],
};

// a reply keyboard whose buttons ask telegram to attach the user's contact/location — the
// panel renders both as `[contact]`/`[location]` placeholders in the timeline.
const shareKeyboard = {
	keyboard: [
		[{ text: "share my location", request_location: true }],
		[{ text: "share my contact", request_contact: true }],
	],
	resize_keyboard: true,
	one_time_keyboard: true,
};

bot.command("start", (ctx) =>
	ctx.reply(
		[
			"panel demo is running.",
			"",
			"try text, photos, documents, voice notes, videos, albums, reactions, polls and the",
			"buttons below — everything shows up in the panel, in real time.",
			"",
			"in the panel you can: hand this chat off from the bot to yourself (status pill),",
			"assign it, pin it, reply to a specific message, edit or delete something you sent,",
			"search across every conversation, export this one, and pick a canned response from",
			"the composer's quick-reply menu.",
			"",
			"edit a message you just sent — the panel patches it in place instead of duplicating it.",
			"try /demo for polls, dice and location/contact sharing.",
		].join("\n"),
		{ reply_markup: demoKeyboard },
	),
);

bot.command("demo", async (ctx) => {
	await ctx.reply("Inline keyboard and callback preview", { reply_markup: demoKeyboard });

	await ctx.sendPoll(
		"which panel feature should you try first?",
		["handoff", "search", "canned responses", "reply/edit/delete"],
		{ is_anonymous: false },
	);
	await ctx.sendDice();

	await ctx.reply("share your location or contact — both render as previews in the panel:", {
		reply_markup: shareKeyboard,
	});
});

bot.on("callback_query:data", async (ctx) => {
	const data = ctx.callbackQuery?.data ?? "callback";
	await ctx.answer("recorded in the panel");

	if (data === "panel:media") {
		await ctx.send(
			"send a photo, video, voice note or album. the panel will render it with the media viewer and styled cards.",
		);
		return;
	}

	await ctx.send(`callback data: ${data}`);
});

// echo replies AS a reply to the original message, so the panel's "replying to ..." strip
// shows up in the timeline too.
bot.on("message:text", (ctx) =>
	ctx.reply(`echo: ${ctx.text}`, {
		reply_parameters: { message_id: ctx.message?.message_id ?? 0 },
	}),
);

bot.on("message:location", (ctx) =>
	ctx.reply(`got it — ${ctx.message?.location?.latitude}, ${ctx.message?.location?.longitude}`, {
		reply_markup: { remove_keyboard: true },
	}),
);

bot.on("message:contact", (ctx) =>
	ctx.reply(`thanks, ${ctx.message?.contact?.first_name ?? "friend"}!`, {
		reply_markup: { remove_keyboard: true },
	}),
);

// echo a photo straight back by file_id; shows up both ways in the panel.
bot.on("message:photo", (ctx) => {
	const fileId = ctx.photo?.[ctx.photo.length - 1]?.file_id;
	if (fileId) ctx.sendPhoto(fileId, { caption: "photo preview card" });
});

bot.on("message:video", (ctx) => {
	const fileId = ctx.video?.file_id;
	if (fileId) ctx.sendVideo(fileId, { caption: "video preview card" });
});

bot.on("message:voice", (ctx) => {
	const fileId = ctx.voice?.file_id;
	if (fileId) ctx.sendVoice(fileId, { caption: "voice message style" });
});

bot.on("message:document", (ctx) =>
	ctx.reply("document stored in the panel with file name and mime preview"),
);

// 4. multi-operator login: set ALICE_TOKEN + BOB_TOKEN to demo named logins and the audit
//  trail (every panel-sent message records who sent it). falls back to a single shared
//  PANEL_TOKEN when those aren't set.
const operators: PanelOperator[] | undefined =
	process.env.ALICE_TOKEN && process.env.BOB_TOKEN
		? [
				{ name: "alice", token: process.env.ALICE_TOKEN },
				{ name: "bob", token: process.env.BOB_TOKEN },
			]
		: undefined;

const cannedResponses: CannedResponse[] = [
	{ label: "Greeting", text: "Hey! Thanks for reaching out — how can I help?" },
	{ label: "Hours", text: "We're online 9am-6pm UTC, Monday to Friday." },
	{ label: "Closing", text: "Glad that's sorted — reach out anytime!" },
];

// 5. serve the panel — login, realtime SSE, handoff, search, export, media proxy, uploads.
const handler = panelHandler(bot.api, store, {
	...(operators ? { operators } : { token: process.env.PANEL_TOKEN ?? "" }),
	recordSends: false, // recordOutgoing already logs panel replies
	cannedResponses,
	// ping your own DM when a message arrives and nobody has the panel open — set this to
	// your telegram user/chat id to try it.
	...(process.env.ADMIN_CHAT_ID ? { notifyChatId: process.env.ADMIN_CHAT_ID } : {}),
	rateLimit: { max: 10, windowMs: 60_000 },
	maxUploadBytes: 25 * 1024 * 1024,
	sessionTtlMs: 12 * 60 * 60 * 1000,
	onError: (error, context) => console.error(`[panel:${context}]`, error),
});

serve(handler, {
	port: 3000,
	onListen: ({ port }) => {
		const mode = operators ? `${operators.length} operators` : "single PANEL_TOKEN";
		console.log(`panel: http://localhost:${port} (${mode})`);
	},
});

bot.onStart((info) =>
	console.log(`bot started @${info.username} - DM it, then watch the panel update live`),
);

await bot.start();

import { type Context, callbackData, createBot, InlineKeyboard } from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/payments-stars/.env first (copy .env.example)");
	process.exit(1);
}

const planData = callbackData("plan", { id: String, stars: Number });
interface Plan {
	id: string;
	title: string;
	stars: number;
}

const plans = [
	{ id: "tip", title: "tip jar", stars: 1 },
	{ id: "pro", title: "pro month", stars: 25 },
	{ id: "ship", title: "ship mode", stars: 100 },
] as const satisfies readonly Plan[];

const bot = createBot(token, {
	allowedUpdates: ["message", "callback_query", "pre_checkout_query"],
})
	.command("start", (ctx) =>
		ctx.reply("choose a telegram stars plan:", {
			reply_markup: plans
				.reduce(
					(keyboard, plan) =>
						keyboard
							.text(
								`${plan.title} - ${plan.stars} stars`,
								planData.pack({ id: plan.id, stars: plan.stars }),
							)
							.row(),
					new InlineKeyboard(),
				)
				.build(),
		}),
	)
	.command("buy", (ctx) => sendInvoice(ctx, plans[0]))
	.command("refund", async (ctx) => {
		const chargeId = ctx.args[0];
		const userId = ctx.from?.id;
		if (!chargeId || userId === undefined)
			return ctx.reply("usage: /refund telegram_payment_charge_id");

		await ctx.refundStarPayment({ user_id: userId, telegram_payment_charge_id: chargeId });
		return ctx.reply("refund requested.");
	})
	.callbackQuery(planData.pattern, async (ctx) => {
		const payload = planData.unpack(ctx.callbackQuery.data ?? "");
		const plan = plans.find((item) => item.id === payload?.id) ?? plans[0];
		await ctx.answer(`invoice: ${plan.title}`);
		return sendInvoice(ctx, plan);
	})
	.on("pre_checkout_query", (ctx) => ctx.answer(true))
	.on("message:successful_payment", (ctx) => {
		const payment = ctx.successful_payment;
		return ctx.reply(
			`payment ok: ${payment?.total_amount ?? 0} ${payment?.currency ?? "xtr"}\ncharge: ${payment?.telegram_payment_charge_id ?? "unknown"}`,
		);
	})
	.onStart(async (info) => {
		await bot.api
			.call("setMyCommands", {
				commands: [
					{ command: "start", description: "choose stars plan" },
					{ command: "buy", description: "send default invoice" },
					{ command: "refund", description: "refund stars payment" },
				],
			})
			.catch(() => {});
		console.log(`@${info.username} payments stars is live`);
	});

function sendInvoice(ctx: Context, plan: Plan) {
	const chatId = ctx.chat?.id;
	if (chatId === undefined) return ctx.reply("no chat in this update.");

	return ctx.api.call("sendInvoice", {
		chat_id: chatId,
		title: plan.title,
		description: `demo invoice for ${plan.title}`,
		payload: `plan:${plan.id}`,
		provider_token: "",
		currency: "XTR",
		prices: [{ label: plan.title, amount: plan.stars }],
		start_parameter: `stars_${plan.id}`,
	});
}

