// index.ts
import { Bot } from "@yaebal/core";
import { run } from "@yaebal/runner";
import { createPool, TaskTimeoutError } from "@yaebal/workers";
import { tasks } from "@yaebal/workers/plugin";
import type { Tasks } from "./tasks.js";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/runner-workers/.env first (copy .env.example)");
	process.exit(1);
}

// parse the pool size safely — a bad env value should not silently produce a zero-worker pool.
const parsedSize = Number.parseInt(process.env.WORKER_POOL_SIZE ?? "", 10);
const size = Number.isInteger(parsedSize) && parsedSize > 0 ? parsedSize : 2;

const pool = createPool<Tasks>(new URL("./tasks.ts", import.meta.url), {
	size,
	// every task gets 3s; cpu-heavy score loops that overrun are cancelled cooperatively via signal.
	timeout: 3_000,
	// shed load instead of growing an unbounded backlog under a flood of updates.
	maxQueue: 512,
});

pool.on("worker:crash", ({ worker, code, willRespawn }) =>
	console.error(
		`worker ${worker} crashed (code ${code})${willRespawn ? " — respawning" : " — dead"}`,
	),
);

const bot = new Bot(token)
	// the plugin puts the typed pool on ctx as `ctx.tasks`. the runner drives the loop itself and
	// never fires the bot's stop handlers, so we own shutdown below (onStop: false).
	.install(tasks(pool, { onStop: false }))
	.command("start", (ctx) =>
		ctx.reply(
			[
				"runner workers is live.",
				"updates are processed concurrently, but each chat stays ordered.",
				`worker pool size: ${pool.size}`,
				"try /hash hello, /score launch plan, /stats, /fanout.",
			].join("\n"),
		),
	)
	.command("hash", async (ctx) => {
		const input = ctx.args.join(" ").trim() || "yaebal";
		const digest = await ctx.tasks.run("digest", input);
		return ctx.reply(`sha256(${input})\n${digest}`);
	})
	.command("score", async (ctx) => {
		const text = ctx.args.join(" ").trim() || "ship the bot";
		try {
			const result = await ctx.tasks.run("score", { text, rounds: 50_000_000 });
			return ctx.reply(`score=${result.score}, length=${result.length}`);
		} catch (error) {
			if (error instanceof TaskTimeoutError)
				return ctx.reply("scoring took too long — try shorter text.");
			throw error;
		}
	})
	.command("stats", (ctx) => {
		const s = ctx.tasks.stats();
		return ctx.reply(
			[
				`workers: ${s.ready}/${s.size} ready, ${s.busy} busy, ${s.dead} dead`,
				`tasks: ${s.running} running, ${s.queued} queued`,
				`lifetime: ${s.completed} done, ${s.failed} failed, ${s.restarts} restarts`,
			].join("\n"),
		);
	})
	.command("fanout", async (ctx) => {
		const chatId = ctx.chat?.id;
		if (chatId === undefined) return ctx.reply("no chat in this update.");

		await Promise.all(
			Array.from({ length: 6 }, (_, index) =>
				ctx.api.sendMessage({ chat_id: chatId, text: `fanout message ${index + 1}/6` }),
			),
		);
	})
	.on("message:text", (ctx) => ctx.reply("try /hash text, /score text or /stats."));

await bot.api
	.call("setMyCommands", {
		commands: [
			{ command: "start", description: "show runner status" },
			{ command: "hash", description: "hash text in a worker" },
			{ command: "score", description: "score text in a worker" },
			{ command: "stats", description: "show worker pool stats" },
			{ command: "fanout", description: "send several messages" },
		],
	})
	.catch(() => {});

// surface a bad worker file (crash-on-load) at startup instead of on the first request.
await pool.ready().catch((error) => {
	console.error("worker pool failed to start:", error);
	process.exit(1);
});

const runner = run(bot, {
	concurrency: 32,
	limit: 100,
	onError: (error) => console.error("runner error", error),
});

console.log(`runner workers is polling with ${pool.size} worker thread(s)`);

async function shutdown() {
	await runner.stop();
	await pool.close({ timeout: 5_000 }); // let in-flight tasks finish, then force-terminate
}

process.once("SIGINT", () => void shutdown());
process.once("SIGTERM", () => void shutdown());

// tasks.ts
import { createHash } from "node:crypto";
import { register } from "@yaebal/workers";

/** the task map shared with createPool<Tasks>() in index.ts — names, args and results stay typed on both sides. */
export type Tasks = {
	digest: (input: string) => string;
	score: (input: { text: string; rounds: number }) => { score: number; length: number };
};

register<Tasks>({
	digest: (input) => createHash("sha256").update(input).digest("hex"),

	// a deliberately cpu-heavy loop. it watches `signal` so a run() timeout (or abort) cancels it
	// promptly and the worker lives to serve the next task instead of being killed.
	score: ({ text, rounds }, { signal }) => {
		let score = 0;
		for (let i = 0; i < rounds; i++) {
			if ((i & 0xffff) === 0 && signal.aborted) throw new Error("scoring aborted");
			const code = text.charCodeAt(i % Math.max(1, text.length)) || 1;
			score = (score + code * (i + 17)) % 1_000_003;
		}

		return { score, length: text.length };
	},
});

import { fileStorage } from "@yaebal/sklad/file";
import {
	clearSession,
	createBot,
	keyBy,
	type StorageAdapter,
	session,
	type TtlValue,
	ttl,
	unwrapTtl,
} from "yaebal";

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/session/.env first (copy .env.example)");
	process.exit(1);
}

// wrap any adapter with logging so the dirty-check is visible in the terminal:
// /count logs a write, /noop logs none — unchanged sessions are never persisted.
function logged<T>(name: string, inner: StorageAdapter<T>): StorageAdapter<T> {
	return {
		get: (key) => {
			console.log(`[${name}] get ${key}`);
			return inner.get(key);
		},
		set: (key, value) => {
			console.log(`[${name}] set ${key} ← ${JSON.stringify(value)}`);
			return inner.set(key, value);
		},
		delete: (key) => {
			console.log(`[${name}] delete ${key}`);
			return inner.delete(key);
		},
	};
}

interface ChatSession {
	count: number;
	since: string;
}

interface Profile {
	visits: number;
	otp?: TtlValue<string>;
}

const bot = createBot(token)
	// per-chat state in a json file — restart the bot and /count keeps counting.
	// the `migrations` block upgrades records written by older versions of this bot
	// ({ count } → { count, since }) the first time they are read.
	.install(
		session({
			initial: (): ChatSession => ({ count: 0, since: new Date().toISOString() }),
			storage: logged("chat", fileStorage<ChatSession>("./data/sessions.json", { pretty: true })),
			migrations: {
				1: (old) => ({ ...(old as { count: number }), since: "before migrations" }),
			},
		}),
	)
	// a second, independent session: per *user* (works across chats and inline queries),
	// under its own field. annotate `initial`'s return type — both generics infer from it.
	.install(
		session({
			key: "profile",
			getKey: keyBy.user,
			initial: (): Profile => ({ visits: 0 }),
			storage: logged("profile", fileStorage<Profile>("./data/profiles.json", { pretty: true })),
		}),
	);

bot.command("start", (ctx) =>
	ctx.reply(
		[
			"session demo:",
			"/count — per-chat counter (persisted to ./data, survives restarts)",
			"/noop — reads the session without changing it (watch the terminal: no write)",
			"/me — per-user visit counter (independent second session)",
			"/otp — issue a code that expires in 30s",
			"/check — see whether the code is still valid",
			"/reset — wipe both sessions",
		].join("\n"),
	),
);

bot.command("count", (ctx) => {
	ctx.session.count++;
	return ctx.reply(`count = ${ctx.session.count} (chat session since ${ctx.session.since})`);
});

bot.command("noop", (ctx) => {
	// read-only handler: the dirty-check skips the write — check your terminal
	return ctx.reply(`current count is ${ctx.session.count}; nothing was written to storage`);
});

bot.command("me", (ctx) => {
	ctx.profile.visits++;
	return ctx.reply(
		`you (${ctx.from?.id}) used this bot ${ctx.profile.visits} time(s), in any chat`,
	);
});

bot.command("otp", (ctx) => {
	const code = Math.random().toString(36).slice(2, 8);
	ctx.profile.otp = ttl(code, 30_000); // self-expiring field
	return ctx.reply(`your code: ${code} (valid 30s — try /check now and after)`);
});

bot.command("check", (ctx) => {
	const code = unwrapTtl(ctx.profile.otp);
	return ctx.reply(
		code === undefined ? "code expired (or never issued)" : `code still valid: ${code}`,
	);
});

bot.command("reset", async (ctx) => {
	await clearSession(ctx); // deletes the chat session record + fresh initial()
	await clearSession(ctx, "profile"); // same for the per-user one
	return ctx.reply("both sessions wiped — /count starts over");
});

bot.start();
console.log("session example running — talk to your bot and watch this terminal");

import { defineMachine, type MachineContext, stateMachine } from "@yaebal/state-machine";
import { type Context, createBot } from "yaebal";

// a focused tour of @yaebal/state-machine.
//
// pnpm --filter @yaebal/example-state-machine dev (needs BOT_TOKEN in .env)

const token = process.env.BOT_TOKEN;
if (!token) {
	console.error("set BOT_TOKEN in examples/state-machine/.env first (copy .env.example)");
	process.exit(1);
}

type OrderEvent = { type: "PAY" } | { type: "SHIP" } | { type: "DELIVER" } | { type: "CANCEL" };

interface OrderContext {
	paidAt?: number;
	cancelLocked: boolean;
}

type OrderCtx = MachineContext<Context, OrderEvent, OrderContext>;

const order = defineMachine<Context, OrderEvent, OrderContext>({
	initial: "created",
	context: () => ({ cancelLocked: false }),
	states: {
		created: {
			// info.from is undefined on the very first activation, set after a /reset
			onEnter: (ctx, info) => info.from !== undefined && ctx.send("starting a new order."),
			on: {
				PAY: {
					target: "paid",
					actions: (ctx) => {
						ctx.machine.context.paidAt = Date.now();
					},
				},
				CANCEL: { target: "cancelled" },
			},
		},
		paid: {
			onEnter: (ctx) => ctx.send("payment received - ship when ready with /ship."),
			on: {
				SHIP: { target: "shipped", guard: (ctx) => ctx.machine.context.paidAt !== undefined },
				CANCEL: {
					target: "cancelled",
					guard: (ctx) => !ctx.machine.context.cancelLocked,
				},
			},
		},
		shipped: {
			onEnter: (ctx) => ctx.send("shipped 📦 - mark it delivered with /deliver."),
			on: {
				DELIVER: { target: "delivered" },
			},
		},
		delivered: {
			onEnter: (ctx) => ctx.send("delivered ✅ this order is done. /reset to start another."),
		},
		cancelled: {
			onEnter: (ctx) => ctx.send("order cancelled. /reset to start another."),
		},
	},
});

async function sendEvent(ctx: OrderCtx, event: OrderEvent): Promise<unknown> {
	if (!ctx.machine.can(event.type)) {
		return ctx.reply(`can't ${event.type.toLowerCase()} from "${ctx.machine.state}".`);
	}

	const moved = await ctx.machine.send(event);
	if (!moved) return ctx.reply("blocked - a guard rejected that transition.");
}

const bot = createBot(token)
	.install(stateMachine(order))
	.command("start", (ctx) =>
		ctx.reply(
			"a focused tour of @yaebal/state-machine. commands: /status /pay /ship /deliver /cancel /lockcancel /reset",
		),
	)
	.command("status", (ctx) =>
		ctx.reply(`state=${ctx.machine.state} context=${JSON.stringify(ctx.machine.context)}`),
	)
	.command("pay", (ctx) => sendEvent(ctx, { type: "PAY" }))
	.command("ship", (ctx) => sendEvent(ctx, { type: "SHIP" }))
	.command("deliver", (ctx) => sendEvent(ctx, { type: "DELIVER" }))
	.command("cancel", (ctx) => sendEvent(ctx, { type: "CANCEL" }))
	.command("lockcancel", (ctx) => {
		ctx.machine.context.cancelLocked = true;
		return ctx.reply(
			"cancellation locked for this order - /cancel will now be rejected by the guard.",
		);
	})
	.command("reset", async (ctx) => {
		await ctx.machine.reset();
		return ctx.reply("order reset.");
	})
	.onError((error, ctx) => {
		console.error(`update ${ctx.update.update_id} failed:`, error);
	})
	.onStart(async (info) => {
		await bot.api
			.call("setMyCommands", {
				commands: [
					{ command: "start", description: "show the available commands" },
					{ command: "status", description: "show the current state and context" },
					{ command: "pay", description: "send the PAY event" },
					{ command: "ship", description: "send the SHIP event" },
					{ command: "deliver", description: "send the DELIVER event" },
					{ command: "cancel", description: "send the CANCEL event" },
					{ command: "lockcancel", description: "lock cancellation (guard demo)" },
					{ command: "reset", description: "reset the order to its initial state" },
				],
			})
			.catch(() => {});

		console.log(`@${info.username} is live - DM it /start`);
	});

process.once("SIGINT", () => bot.stop());
process.once("SIGTERM", () => bot.stop());

await bot.start();

